                "sessionId": session_id,
                "modelId": model_id
            })),
        };

        self.send_request_raw(id, request).await
    }

    pub async fn set_mode(&self, session_id: &str, mode_id: &str) -> Result<sj::Value, String> {
        let id = {
            let mut guard = self.request_id.lock().await;
