            })),
        };

        self.send_request_raw(id, request).await
    }

    pub async fn send_prompt(&self, session_id: &str, message: &str) -> Result<PromptResult, String> {
        let id = {
            let mut guard = self.request_id.lock().await;
            let id = *guard;
            *guard += 1;
            id
