/// Load MCP servers from ~/.config/opencode/opencode.json and optionally {cwd}/opencode.json.
/// Project-level config overrides global config by name.
fn load_mcp_servers(cwd: &str) -> Vec<sj::Value> {
    let home = std::env::var("HOME").unwrap_or_default();
    let global_path = format!("{}/.config/opencode/opencode.json", home);
    let project_path = format!("{}/opencode.json", cwd);

    let mut servers: HashMap<String, sj::Value> = HashMap::new();

    for path in [&global_path, &project_path] {
        if let Ok(text) = std::fs::read_to_string(path) {
            // Strip trailing commas (opencode.json uses relaxed JSON)
            let cleaned = strip_trailing_commas(&text);
            if let Ok(config) = sj::from_str::<sj::Value>(&cleaned) {
                if let Some(mcp) = config.get("mcp").and_then(|v| v.as_object()) {
                    for (name, def) in mcp {
                        if def.get("enabled").and_then(|v| v.as_bool()) == Some(false) {
                            continue;
                        }
                        if let Some(server) = mcp_def_to_acp(name, def) {
                            servers.insert(name.clone(), server);
                        }
                    }
                }
            }
        }
    }

    servers.into_values().collect()
}

/// Resolve a command name to its full path, checking common user-local bin dirs.
/// Falls back to the original name if not found (let the OS handle it).
fn resolve_command(cmd: &str) -> String {
    if cmd.starts_with('/') {
        return cmd.to_string();
    }
    let home = std::env::var("HOME").unwrap_or_default();
    let candidates = [
        format!("{}/.local/bin/{}", home, cmd),
        format!("{}/.cargo/bin/{}", home, cmd),
        format!("/usr/local/bin/{}", cmd),
        format!("/usr/bin/{}", cmd),
    ];
    for path in &candidates {
        if std::path::Path::new(path).exists() {
            return path.clone();
        }
    }
    cmd.to_string()
}

fn mcp_def_to_acp(name: &str, def: &sj::Value) -> Option<sj::Value> {
    let typ = def.get("type").and_then(|v| v.as_str()).unwrap_or("local");

    match typ {
        "local" => {
            let cmd_arr = def.get("command").and_then(|v| v.as_array())?;
            let command_str = cmd_arr.first()?.as_str()?;
            // Resolve to full path so OpenCode (running as service) can find it
            let command = resolve_command(command_str);
            let args: Vec<&str> = cmd_arr[1..].iter().filter_map(|v| v.as_str()).collect();
            let env: Vec<sj::Value> = def.get("environment")
                .or_else(|| def.get("env"))
                .and_then(|v| v.as_object())
                .map(|m| m.iter().map(|(k, v)| sj::json!({"name": k, "value": v})).collect())
                .unwrap_or_default();
            // McpServerStdio has no "type" field in the ACP schema
            Some(sj::json!({
                "name": name,
                "command": command,
                "args": args,
                "env": env
            }))
        }
        "http" | "remote" | "sse" => {
            let url = def.get("url").and_then(|v| v.as_str())?;
            let headers: Vec<sj::Value> = def.get("headers")
                .and_then(|v| v.as_object())
                .map(|m| m.iter().map(|(k, v)| sj::json!({"name": k, "value": v})).collect())
                .unwrap_or_default();
            // "remote" maps to "sse" in ACP schema
            let acp_type = if typ == "http" { "http" } else { "sse" };
            Some(sj::json!({
                "name": name,
                "type": acp_type,
                "url": url,
                "headers": headers
            }))
        }
        _ => None,
    }
}

/// Minimal trailing-comma stripper for JSON objects/arrays.
fn strip_trailing_commas(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let bytes = s.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if bytes[i] == b',' {
            // Look ahead past whitespace for } or ]
            let mut j = i + 1;
            while j < bytes.len() && (bytes[j] == b' ' || bytes[j] == b'\t' || bytes[j] == b'\n' || bytes[j] == b'\r') {
                j += 1;
            }
            if j < bytes.len() && (bytes[j] == b'}' || bytes[j] == b']') {
                i += 1; // skip the comma
                continue;
            }
        }
        out.push(bytes[i] as char);
        i += 1;
    }
    out
}

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct JsonRpcRequest {
    pub jsonrpc: String,
    pub id: serde_json::Value,
    pub method: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub params: Option<serde_json::Value>,
}


#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct JsonRpcResponse {
    pub jsonrpc: String,
    pub id: serde_json::Value,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub result: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<JsonRpcError>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct JsonRpcError {
    pub code: i32,
    pub message: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub data: Option<serde_json::Value>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct JsonRpcNotification {
    pub jsonrpc: String,
    pub method: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub params: Option<serde_json::Value>,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(untagged)]
pub enum JsonRpcMessage {
    Request(JsonRpcRequest),
    Response(JsonRpcResponse),
    Notification(JsonRpcNotification),
}

pub fn parse_jsonrpc_message(line: &str) -> Option<JsonRpcMessage> {
    if !line.starts_with('{') {
        tracing::debug!("ACP stdout (non-JSON): {}", line);
        return None;
    }
    match serde_json::from_str::<JsonRpcMessage>(line) {
        Ok(msg) => Some(msg),
        Err(e) => {
            tracing::error!("Failed to parse JSON-RPC message: {} - Line: {}", e, line);
            None
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn test_parse_jsonrpc_request() {
        let line = r#"{"jsonrpc":"2.0","id":1,"method":"initialize","params":{}}"#;
        let msg = parse_jsonrpc_message(line).unwrap();
        match msg {
            JsonRpcMessage::Request(req) => {
                assert_eq!(req.method, "initialize");
                assert_eq!(req.jsonrpc, "2.0");
            }
            _ => panic!("Expected Request"),
        }
    }

    #[test]
    fn test_parse_jsonrpc_response() {
        let line = r#"{"jsonrpc":"2.0","id":1,"result":{"status":"ok"}}"#;
        let msg = parse_jsonrpc_message(line).unwrap();
        match msg {
            JsonRpcMessage::Response(resp) => {
                assert_eq!(resp.id, json!(1));
                assert!(resp.result.is_some());
            }
            _ => panic!("Expected Response"),
        }
    }

    #[test]
    fn test_parse_jsonrpc_notification() {
        let line = r#"{"jsonrpc":"2.0","method":"update","params":{"x":1}}"#;
        let msg = parse_jsonrpc_message(line).unwrap();
        match msg {
            JsonRpcMessage::Notification(notif) => {
                assert_eq!(notif.method, "update");
            }
            _ => panic!("Expected Notification"),
        }
    }

    #[test]
    fn test_parse_non_json_returns_none() {
        assert!(parse_jsonrpc_message("not json").is_none());
        assert!(parse_jsonrpc_message("").is_none());
    }

    #[test]
    fn test_parse_invalid_json_returns_none() {
        assert!(parse_jsonrpc_message("{invalid}").is_none());
    }

    #[test]
    fn test_jsonrpc_error_serialization() {
        let err = JsonRpcError {
            code: -32601,
            message: "Method not found".to_string(),
            data: None,
        };
        let json_str = serde_json::to_string(&err).unwrap();
        assert!(json_str.contains("Method not found"));
        assert!(json_str.contains("-32601"));
    }

    #[test]
    fn test_jsonrpc_request_no_params() {
        let req = JsonRpcRequest {
            jsonrpc: "2.0".to_string(),
            id: json!(42),
            method: "ping".to_string(),
            params: None,
        };
        let json_str = serde_json::to_string(&req).unwrap();
        assert!(!json_str.contains("params")); // skip_serializing_if
    }
}

