type AudioClient = mpsc::UnboundedSender<BroadcastMessage>;

lazy_static::lazy_static! {
    static ref AUDIO_STATE: Arc<Mutex<AudioState>> = Arc::new(Mutex::new(AudioState::default()));
}

#[derive(Default)]
struct AudioState {
    ffmpeg_process: Option<Child>,
    is_streaming: bool,
    clients: Vec<AudioClient>,
}

pub async fn start_streaming(client_tx: mpsc::UnboundedSender<BroadcastMessage>) -> Result<()> {
    let mut state = AUDIO_STATE.lock().await;

    // Add client
    state.clients.push(client_tx.clone());
    tracing::info!("Audio client added. Total clients: {}", state.clients.len());

    // Send current status
    let status = ServerMessage::AudioStatus {
        streaming: state.is_streaming,
        error: None,
    };
    if let Ok(json) = serde_json::to_string(&status) {
        let _ = client_tx.send(BroadcastMessage::Text(Arc::new(json)));
    }

    // Start streaming if not already running
    if !state.is_streaming {
        start_ffmpeg(&mut state).await?;
    }

    Ok(())
}

pub async fn stop_streaming_for_client(
    client_tx: &mpsc::UnboundedSender<BroadcastMessage>,
) -> Result<()> {
    let mut state = AUDIO_STATE.lock().await;

    // Send stop status to the client first
    let status = ServerMessage::AudioStatus {
        streaming: false,
        error: None,
    };
    if let Ok(json) = serde_json::to_string(&status) {
        let _ = client_tx.send(BroadcastMessage::Text(Arc::new(json)));
    }

    // Remove only this specific client
    state.clients.retain(|c| !c.same_channel(client_tx));
    tracing::info!(
        "Audio client removed. Remaining clients: {}",
        state.clients.len()
    );

    // Only stop ffmpeg if no clients remain
    if state.clients.is_empty() && state.is_streaming {
        stop_ffmpeg(&mut state).await;
    }

    Ok(())
}

async fn get_default_monitor_source() -> Result<String> {
    // Get the default sink first
    let output = Command::new("pactl")
        .args(&["get-default-sink"])
        .output()
        .await?;

    if !output.status.success() {
        return Err(anyhow::anyhow!("Failed to get default sink"));
    }

    let sink = String::from_utf8_lossy(&output.stdout).trim().to_string();
    // Append .monitor to get the monitor source
    Ok(format!("{}.monitor", sink))
}

async fn start_ffmpeg(state: &mut AudioState) -> Result<()> {
    tracing::info!("Starting audio streaming...");
    state.is_streaming = true;

    // Determine platform-specific input args
    let (input_source, input_args) = if cfg!(target_os = "linux") {
        // First try to get the default monitor source
        match get_default_monitor_source().await {
            Ok(source) => {
                tracing::info!("Using PulseAudio monitor source: {}", source);
                (source, vec!["-f", "pulse", "-i"])
            }
            Err(_) => {
                tracing::info!("Using default PulseAudio source");
                ("default".to_string(), vec!["-f", "pulse", "-i"])
            }
        }
    } else if cfg!(target_os = "macos") {
        (":0".to_string(), vec!["-f", "avfoundation", "-i"])
    } else {
        error!("Unsupported platform for audio capture");
        state.is_streaming = false;
        notify_clients_error(state, "Unsupported platform for audio capture").await;
        return Err(anyhow::anyhow!("Unsupported platform"));
    };

    // Spawn ffmpeg process
    let mut child = Command::new("ffmpeg")
        .args(&input_args)
        .arg(&input_source)
        .args(&[
            "-acodec", "libopus", "-b:a", "128k", "-ar", "48000", "-ac", "2", "-f", "webm", "-",
        ])
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    // Get stdout for reading audio data
    let mut stdout = child.stdout.take().unwrap();

    // Clone clients for the spawned task
    let clients_clone: Vec<AudioClient> = state.clients.clone();

    // Spawn task to read and broadcast audio data
    tokio::spawn(async move {
        let mut buffer = vec![0u8; 16384]; // Larger buffer for better throughput
        loop {
            match stdout.read(&mut buffer).await {
                Ok(0) => break, // EOF
                Ok(n) => {
                    // Convert to base64 and send as JSON for client compatibility
                    let base64_data = STANDARD.encode(&buffer[..n]);
                    let msg = ServerMessage::AudioStream { data: base64_data };
                    tracing::info!("Sending audio chunk: {} bytes", n);
                    broadcast_json_to_clients(&clients_clone, msg).await;
                }
                Err(e) => {
                    error!("Error reading ffmpeg output: {}", e);
                    break;
                }
            }
        }
    });

    // Spawn task to monitor stderr
    if let Some(mut stderr) = child.stderr.take() {
        tokio::spawn(async move {
            let mut buffer = vec![0u8; 1024];
            while let Ok(n) = stderr.read(&mut buffer).await {
                if n == 0 {
                    break;
                }
                if crate::ENABLE_AUDIO_LOGS.load(std::sync::atomic::Ordering::Relaxed) {
                    let log = String::from_utf8_lossy(&buffer[..n]);
                    tracing::info!("FFmpeg: {}", log);
                }
            }
        });
    }

    state.ffmpeg_process = Some(child);

    // Notify clients that streaming started
    notify_clients_status(state, true).await;

    Ok(())
}

async fn stop_ffmpeg(state: &mut AudioState) {
    tracing::info!("Stopping audio streaming...");

    if let Some(mut child) = state.ffmpeg_process.take() {
        let _ = child.kill().await;
    }

    state.is_streaming = false;
    notify_clients_status(state, false).await;
}

async fn notify_clients_status(state: &AudioState, streaming: bool) {
    let msg = ServerMessage::AudioStatus {
        streaming,
        error: None,
    };
    if let Ok(json) = serde_json::to_string(&msg) {
        let broadcast_msg = BroadcastMessage::Text(Arc::new(json));
        for client in &state.clients {
            let _ = client.send(broadcast_msg.clone());
        }
    }
}

async fn notify_clients_error(state: &AudioState, error: &str) {
    let msg = ServerMessage::AudioStatus {
        streaming: false,
        error: Some(error.to_string()),
    };
    if let Ok(json) = serde_json::to_string(&msg) {
        let broadcast_msg = BroadcastMessage::Text(Arc::new(json));
        for client in &state.clients {
            let _ = client.send(broadcast_msg.clone());
        }
    }
}

async fn broadcast_json_to_clients<T: serde::Serialize>(clients: &[AudioClient], message: T) {
    if let Ok(json) = serde_json::to_string(&message) {
        let msg = BroadcastMessage::Text(Arc::new(json));
        for client in clients {
            let _ = client.send(msg.clone());
        }
    }
}

use axum::{extract::Request, http::StatusCode, middleware::Next, response::Response};
use subtle::ConstantTimeEq;
use tracing::warn;

/// Read AUTH_TOKEN from environment. Panics at startup if not set or empty.
/// Call `require_auth_token()` once during startup to enforce this invariant.
fn expected_token() -> String {
    let token = std::env::var("AUTH_TOKEN")
        .unwrap_or_default();
    if token.is_empty() {
        eprintln!("FATAL: AUTH_TOKEN environment variable is not set or is empty.");
        eprintln!("Set AUTH_TOKEN to a strong secret before starting the server.");
        std::process::exit(1);
    }
    token
}

/// Call once at startup to abort if AUTH_TOKEN is missing.
pub fn require_auth_token() {
    let _ = expected_token();
}

/// Extract token value from a query string like "foo=bar&token=secret&baz=1"
fn extract_token_from_query(query: &str) -> Option<String> {
    for pair in query.split('&') {
        if let Some(value) = pair.strip_prefix("token=") {
            // URL-decode the value
            return Some(percent_decode(value.as_bytes()));
        }
    }
    None
}

/// Simple percent-decoding (handles %XX sequences)
fn percent_decode(input: &[u8]) -> String {
    let mut output = Vec::with_capacity(input.len());
    let mut i = 0;
    while i < input.len() {
        if input[i] == b'%' && i + 2 < input.len() {
            if let Ok(byte) = u8::from_str_radix(
                &String::from_utf8_lossy(&input[i + 1..i + 3]),
                16,
            ) {
                output.push(byte);
                i += 3;
                continue;
            }
        }
        output.push(input[i]);
        i += 1;
    }
    String::from_utf8_lossy(&output).to_string()
}

/// Constant-time token comparison to prevent timing attacks.
fn tokens_match(provided: &str, expected: &str) -> bool {
    // Constant-time comparison — both length and content are compared
    // without leaking information through timing side-channels.
    provided.as_bytes().ct_eq(expected.as_bytes()).into()
}

/// Return the request path without query string (strips token from logged URIs).
fn safe_path(request: &Request) -> &str {
    request.uri().path()
}

/// Middleware that validates the auth token from query param or header.
/// AUTH_TOKEN must be set — if it isn't, the server exits at startup.
pub async fn auth_middleware(request: Request, next: Next) -> Result<Response, StatusCode> {
    let expected = expected_token();

    // Check query parameter first (?token=xxx)
    let token_from_query = request
        .uri()
        .query()
        .and_then(extract_token_from_query);

    // Check X-Auth-Token header as fallback
    let token_from_header = request
        .headers()
        .get("X-Auth-Token")
        .and_then(|v| v.to_str().ok())
        .map(String::from);

    let provided = token_from_query.or(token_from_header);

    match provided {
        Some(ref t) if tokens_match(t, &expected) => Ok(next.run(request).await),
        Some(_) => {
            warn!(
                "Rejected request with invalid auth token: {} {}",
                request.method(),
                safe_path(&request)
            );
            Err(StatusCode::UNAUTHORIZED)
        }
        None => {
            warn!(
                "Rejected request with missing auth token: {} {}",
                request.method(),
                safe_path(&request)
            );
            Err(StatusCode::UNAUTHORIZED)
        }
    }
}

#[cfg(test)]
