            r#"{"type":"item.started","item":{"id":"item_1","type":"agent_message","text":"starting"}}"#,
            r#"{"type":"item.updated","item":{"id":"item_1","type":"agent_message","text":"updating"}}"#,
        ];
        for line in &cases {
