        let pid = std::process::id();
        let result = get_descendant_pids(pid);
        assert!(result.is_ok());
        let pids = result.unwrap();
        assert!(pids.contains(&pid));
    }

    #[test]
    fn test_direct_children_does_not_panic() {
        let children = direct_children(1); // init/systemd always exists on Linux
        // May be empty or have some children — just shouldn't panic
        let _ = children;
    }

    #[test]
    fn test_process_name_self() {
        let pid = std::process::id();
        let name = process_name(pid);
        // Should return something for our own process
        assert!(name.is_some());
    }

    #[test]
    fn test_process_name_nonexistent() {
        // PID 0 doesn't have a /proc entry
        let name = process_name(0);
        assert!(name.is_none());
    }

    #[test]
    fn test_get_process_cwd_self() {
        let pid = std::process::id();
        let result = get_process_cwd(pid);
        assert!(result.is_ok());
    }

    #[test]
    fn test_get_process_cwd_nonexistent() {
        let result = get_process_cwd(999999999);
        assert!(result.is_err());
    }

    #[test]
    fn test_newest_jsonl_in_empty_dir() {
        let dir = tempfile::TempDir::new().unwrap();
        let result = newest_jsonl_in(dir.path());
        assert!(result.is_none());
    }

    #[test]
    fn test_newest_jsonl_in_with_files() {
        let dir = tempfile::TempDir::new().unwrap();
        std::fs::write(dir.path().join("old.jsonl"), "{}").unwrap();
        std::thread::sleep(std::time::Duration::from_millis(10));
        std::fs::write(dir.path().join("newer.jsonl"), "{}").unwrap();
        let result = newest_jsonl_in(dir.path());
        assert!(result.is_some());
        // Should return the newer file
        assert!(result.unwrap().file_name().unwrap().to_str().unwrap().ends_with(".jsonl"));
    }

    #[test]
    fn test_newest_jsonl_ignores_non_jsonl() {
        let dir = tempfile::TempDir::new().unwrap();
        std::fs::write(dir.path().join("file.txt"), "{}").unwrap();
        std::fs::write(dir.path().join("data.json"), "{}").unwrap();
        let result = newest_jsonl_in(dir.path());
        assert!(result.is_none()); // No .jsonl files
    }

    #[test]
    fn test_parse_line_invalid_json() {
        let result = parse_line("not json at all", &AiTool::Claude);
        assert!(result.is_none());
    }

    #[test]
    fn test_parse_line_codex_invalid() {
        let result = parse_line("not json", &AiTool::Codex);
        assert!(result.is_none());
    }

    #[test]
    fn test_parse_line_opencode_always_none() {
        let result = parse_line("{}", &AiTool::Opencode { pid: 0, cwd: std::path::PathBuf::new() });
        assert!(result.is_none());
    }

    #[test]
    fn test_is_process_alive_with_cwd_self() {
        let pid = std::process::id();
        let cwd = std::env::current_dir().unwrap();
        // May be true or false depending on CWD match — just should not panic
        let _ = is_process_alive_with_cwd(pid, &cwd);
    }

    #[test]
    fn test_is_process_alive_nonexistent_pid() {
        let result = is_process_alive_with_cwd(999999999, std::path::Path::new("/"));
        assert!(!result);
    }
}

use anyhow::Result;
use chrono::{DateTime, Utc};
use std::collections::HashMap;
use std::process::Command;
use tokio::sync::RwLock;
use tracing::info;
use uuid::Uuid;

use crate::types::CronJob;

pub struct CronManager {
    jobs: RwLock<HashMap<String, CronJob>>,
}

impl CronManager {
    pub fn new() -> Self {
        Self {
            jobs: RwLock::new(HashMap::new()),
        }
    }

    pub async fn initialize(&self) -> Result<()> {
        // Load existing cron jobs from system crontab
        self.load_from_crontab().await?;
        Ok(())
    }

    pub async fn list_jobs(&self) -> Vec<CronJob> {
        let jobs = self.jobs.read().await;
        let mut job_list: Vec<CronJob> = jobs.values().cloned().collect();
        job_list.sort_by(|a, b| a.created_at.cmp(&b.created_at).reverse());
        job_list
    }

    pub async fn create_job(&self, mut job: CronJob) -> Result<CronJob> {
        // Generate ID if not provided
        if job.id.is_empty() {
            job.id = Uuid::new_v4().to_string();
        }

        // Check for duplicate names
        {
            let jobs = self.jobs.read().await;
            if jobs.values().any(|j| j.name == job.name && j.id != job.id) {
                return Err(anyhow::anyhow!(
                    "A job with the name '{}' already exists",
                    job.name
                ));
            }
        }

        // Set timestamps
        let now = Utc::now();
        job.created_at = Some(now);
        job.updated_at = Some(now);

        // Validate cron expression
        self.validate_cron_expression(&job.schedule)?;

        // Calculate next run time
        job.next_run = self.calculate_next_run(&job.schedule).unwrap_or(None);

        // Add to crontab
        self.add_to_crontab(&job).await?;

        // Store in memory
        let mut jobs = self.jobs.write().await;
        jobs.insert(job.id.clone(), job.clone());

        info!("Created cron job: {} ({})", job.name, job.id);
        Ok(job)
    }

    pub async fn update_job(&self, id: String, mut job: CronJob) -> Result<CronJob> {
        // Check for duplicate names (excluding self)
        {
            let jobs = self.jobs.read().await;
            if jobs.values().any(|j| j.name == job.name && j.id != id) {
                return Err(anyhow::anyhow!(
                    "A job with the name '{}' already exists",
                    job.name
                ));
            }
        }

        // Validate cron expression
        self.validate_cron_expression(&job.schedule)?;

        // Update timestamp
        job.updated_at = Some(Utc::now());
        job.id = id.clone();

        // Calculate next run time
        job.next_run = self.calculate_next_run(&job.schedule).unwrap_or(None);

        // Remove old entry from crontab
        self.remove_from_crontab(&id).await?;

        // Always add to crontab (enabled status is stored in comments)
        self.add_to_crontab(&job).await?;

        // Update in memory
        let mut jobs = self.jobs.write().await;
        jobs.insert(id, job.clone());

        info!("Updated cron job: {} ({})", job.name, job.id);
        Ok(job)
    }

    pub async fn delete_job(&self, id: &str) -> Result<()> {
        // Remove from crontab
        self.remove_from_crontab(id).await?;

        // Remove from memory
        let mut jobs = self.jobs.write().await;
        if let Some(job) = jobs.remove(id) {
            info!("Deleted cron job: {} ({})", job.name, id);
        }

        Ok(())
    }

    pub async fn toggle_job(&self, id: &str, enabled: bool) -> Result<CronJob> {
        let mut jobs = self.jobs.write().await;

        if let Some(job) = jobs.get_mut(id) {
            job.enabled = enabled;
            job.updated_at = Some(Utc::now());

            // Always remove first to avoid duplicates
            self.remove_from_crontab(id).await?;

            // Then add back with updated status
            self.add_to_crontab(job).await?;

            info!(
                "Toggled cron job: {} ({}) - enabled: {}",
                job.name, id, enabled
            );
            Ok(job.clone())
        } else {
            Err(anyhow::anyhow!("Job not found: {}", id))
        }
    }

    pub async fn test_command(&self, command: &str) -> Result<String> {
        info!("Dry-run test for cron command: {}", command);

        // Validate the command is not empty
        let command = command.trim();
        if command.is_empty() {
            return Err(anyhow::anyhow!("Command is empty"));
        }

        // Dry-run only: return what would be executed without running it.
        // Shell execution is intentionally disabled — arbitrary `sh -c` is an RCE vector.
        Ok(format!(
            "Dry-run: the following command would be executed by cron:\n{}",
            command
        ))
    }

    // Private helper methods

    async fn load_from_crontab(&self) -> Result<()> {
        let output = Command::new("crontab").arg("-l").output()?;

        if !output.status.success() {
            // No crontab or empty crontab is fine
            return Ok(());
        }

        let crontab_content = String::from_utf8_lossy(&output.stdout);
        let mut jobs = self.jobs.write().await;

        // Parse AgentShell-managed jobs from crontab
        // Look for special comment markers
        let lines: Vec<&str> = crontab_content.lines().collect();
        let mut i = 0;

        while i < lines.len() {
            if lines[i].starts_with("# AgentShell-Job-Start:") {
                if let Some(job_id) = lines[i].strip_prefix("# AgentShell-Job-Start:") {
                    let job_id = job_id.trim();

                    // Parse job metadata from comments
                    let mut job_name = String::new();
                    let mut enabled = true;

                    i += 1;
                    while i < lines.len() && !lines[i].starts_with("# AgentShell-Job-End") {
                        if lines[i].starts_with("# Name:") {
                            job_name = lines[i]
                                .strip_prefix("# Name:")
                                .unwrap_or("")
                                .trim()
                                .to_string();
                        } else if lines[i].starts_with("# Enabled:") {
                            enabled = lines[i].strip_prefix("# Enabled:").unwrap_or("true").trim()
                                == "true";
                        } else if !lines[i].trim().is_empty() {
                            // This could be the actual cron line (active or commented out)
                            let line = if lines[i].starts_with("# ") && enabled == false {
                                // Disabled job - remove the comment prefix
                                lines[i].strip_prefix("# ").unwrap_or(lines[i])
                            } else if !lines[i].starts_with("#") {
                                // Active job
                                lines[i]
                            } else {
                                i += 1;
                                continue;
                            };

                            let parts: Vec<&str> = line.splitn(6, ' ').collect();
                            if parts.len() >= 6 {
                                let schedule = parts[0..5].join(" ");
                                let command = parts[5].to_string();

                                let job = CronJob {
                                    id: job_id.to_string(),
                                    name: job_name.clone(),
                                    schedule,
                                    command,
                                    enabled,
                                    last_run: None,
                                    next_run: self
                                        .calculate_next_run(&parts[0..5].join(" "))
                                        .unwrap_or(None),
                                    output: None,
                                    created_at: Some(Utc::now()),
                                    updated_at: Some(Utc::now()),
                                    environment: None,
                                    log_output: None,
                                    email_to: None,
                                    tmux_session: None,
                                };

                                jobs.insert(job_id.to_string(), job);
                            }
                        }
                        i += 1;
                    }
                }
            }
            i += 1;
        }

        info!("Loaded {} cron jobs from crontab", jobs.len());
        Ok(())
    }

    async fn add_to_crontab(&self, job: &CronJob) -> Result<()> {
        // Get current crontab
        let output = Command::new("crontab").arg("-l").output()?;

        let mut crontab_content = if output.status.success() {
            String::from_utf8_lossy(&output.stdout).to_string()
        } else {
            String::new()
        };

        // Add job with AgentShell markers
        let job_entry = if job.enabled {
            // Active job - include the cron line
            format!(
                "\n# AgentShell-Job-Start:{}\n# Name:{}\n# Enabled:{}\n{} {}\n# AgentShell-Job-End:{}\n",
                job.id, job.name, job.enabled, job.schedule, job.command, job.id
            )
        } else {
            // Disabled job - comment out the cron line
            format!(
                "\n# AgentShell-Job-Start:{}\n# Name:{}\n# Enabled:{}\n# {} {}\n# AgentShell-Job-End:{}\n",
                job.id, job.name, job.enabled, job.schedule, job.command, job.id
            )
        };

        crontab_content.push_str(&job_entry);

        // Write back to crontab
        self.write_crontab(&crontab_content).await?;

        Ok(())
    }

    async fn remove_from_crontab(&self, id: &str) -> Result<()> {
        // Get current crontab
        let output = Command::new("crontab").arg("-l").output()?;

        if !output.status.success() {
            return Ok(());
        }

        let crontab_content = String::from_utf8_lossy(&output.stdout);
        let lines: Vec<&str> = crontab_content.lines().collect();
        let mut new_lines = Vec::new();
        let mut i = 0;
        let mut skip = false;

        while i < lines.len() {
            if lines[i] == &format!("# AgentShell-Job-Start:{}", id) {
                skip = true;
            } else if lines[i] == &format!("# AgentShell-Job-End:{}", id) {
                skip = false;
                i += 1;
                continue;
            }

            if !skip {
                new_lines.push(lines[i]);
            }

            i += 1;
        }

        let new_crontab = new_lines.join("\n");
        self.write_crontab(&new_crontab).await?;

        Ok(())
    }

    async fn write_crontab(&self, content: &str) -> Result<()> {
        use std::io::Write;
        use std::process::Stdio;

        let mut child = Command::new("crontab")
            .arg("-")
            .stdin(Stdio::piped())
            .spawn()?;

        if let Some(mut stdin) = child.stdin.take() {
            stdin.write_all(content.as_bytes())?;
            stdin.flush()?;
        }

        let status = child.wait()?;
        if !status.success() {
            return Err(anyhow::anyhow!("Failed to write crontab"));
        }

        Ok(())
    }

    fn validate_cron_expression(&self, expression: &str) -> Result<()> {
        use cron::Schedule;
        use std::str::FromStr;

        let parts: Vec<&str> = expression.split_whitespace().collect();
        if parts.len() != 5 {
            return Err(anyhow::anyhow!(
                "Invalid cron expression: expected 5 fields, got {}",
                parts.len()
            ));
        }

        // Validate by attempting to parse with the cron crate
        let extended = format!("0 {} *", expression);
        Schedule::from_str(&extended)
            .map_err(|e| anyhow::anyhow!("Invalid cron expression '{}': {}", expression, e))?;

        Ok(())
    }

    fn calculate_next_run(&self, schedule: &str) -> Result<Option<DateTime<Utc>>> {
        use cron::Schedule;
        use std::str::FromStr;

        // Standard cron uses 5 fields: min hour dom month dow
        // The `cron` crate expects 7 fields: sec min hour dom month dow year
        let extended = format!("0 {} *", schedule);

        let sched = Schedule::from_str(&extended)
            .map_err(|e| anyhow::anyhow!("Invalid cron expression '{}': {}", schedule, e))?;

        Ok(sched.upcoming(Utc).next())
    }
}

lazy_static::lazy_static! {
    pub static ref CRON_MANAGER: CronManager = CronManager::new();
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_manager() -> CronManager {
        CronManager::new()
    }

    #[test]
    fn test_validate_valid_expressions() {
        let mgr = make_manager();
        assert!(mgr.validate_cron_expression("* * * * *").is_ok());
        assert!(mgr.validate_cron_expression("0 12 * * *").is_ok());
        assert!(mgr.validate_cron_expression("*/5 * * * *").is_ok());
        assert!(mgr.validate_cron_expression("0 0 1 1 *").is_ok());
        assert!(mgr.validate_cron_expression("0 8-18 * * 1-5").is_ok());
    }

    #[test]
    fn test_validate_wrong_field_count() {
        let mgr = make_manager();
        assert!(mgr.validate_cron_expression("* * *").is_err());
        assert!(mgr.validate_cron_expression("* * * * * *").is_err()); // 6 fields
        assert!(mgr.validate_cron_expression("").is_err());
    }

    #[test]
    fn test_validate_invalid_expression() {
        let mgr = make_manager();
        // Invalid range
        assert!(mgr.validate_cron_expression("99 * * * *").is_err());
    }

    #[test]
    fn test_calculate_next_run_valid() {
        let mgr = make_manager();
        let result = mgr.calculate_next_run("* * * * *").unwrap();
        assert!(result.is_some());
        // Should be in the future
        let next = result.unwrap();
        assert!(next > Utc::now() - chrono::Duration::seconds(60));
    }

    #[test]
    fn test_calculate_next_run_invalid() {
        let mgr = make_manager();
        let result = mgr.calculate_next_run("invalid expr");
        assert!(result.is_err());
    }

    #[tokio::test]
    async fn test_list_jobs_empty() {
        let mgr = make_manager();
        let jobs = mgr.list_jobs().await;
        assert!(jobs.is_empty());
    }

    #[tokio::test]
    async fn test_test_command_dry_run() {
        let mgr = make_manager();
        let result = mgr.test_command("echo hello").await;
        assert!(result.is_ok());
        assert!(result.unwrap().contains("Dry-run"));
    }

    #[tokio::test]
    async fn test_test_command_empty() {
        let mgr = make_manager();
        let result = mgr.test_command("  ").await;
        assert!(result.is_err());
    }
}

use anyhow::{Context, Result};
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use tokio::sync::RwLock;
use tracing::info;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DotFile {
    pub name: String,
    pub path: String,
    pub size: u64,
    pub modified: DateTime<Utc>,
    pub exists: bool,
    pub readable: bool,
    pub writable: bool,
    pub file_type: DotFileType,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum DotFileType {
    Shell, // .bashrc, .zshrc, .profile
    Git,   // .gitconfig, .gitignore
    Vim,   // .vimrc, .vim/
    Tmux,  // .tmux.conf
    SSH,   // .ssh/config
    Other,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FileVersion {
    pub timestamp: DateTime<Utc>,
    pub content: String,
    pub size: u64,
    pub hash: String,
}

pub struct DotFilesManager {
    // Store file history in memory for now (could be moved to DB later)
    history: RwLock<HashMap<String, Vec<FileVersion>>>,
    // Common dotfile paths relative to home directory
    common_dotfiles: Vec<(&'static str, DotFileType)>,
}

impl DotFilesManager {
    pub fn new() -> Self {
        Self {
            history: RwLock::new(HashMap::new()),
            common_dotfiles: vec![
                (".bashrc", DotFileType::Shell),
                (".zshrc", DotFileType::Shell),
                (".profile", DotFileType::Shell),
                (".bash_profile", DotFileType::Shell),
                (".bash_aliases", DotFileType::Shell),
                (".gitconfig", DotFileType::Git),
                (".gitignore_global", DotFileType::Git),
                (".vimrc", DotFileType::Vim),
                (".vim/vimrc", DotFileType::Vim),
                (".tmux.conf", DotFileType::Tmux),
                (".ssh/config", DotFileType::SSH),
                (".ssh/authorized_keys", DotFileType::SSH),
                (".ssh/known_hosts", DotFileType::SSH),
            ],
        }
    }

    /// List common dotfiles with their metadata
    pub async fn list_dotfiles(&self) -> Result<Vec<DotFile>> {
        let home_dir = dirs::home_dir()
            .ok_or_else(|| anyhow::anyhow!("Could not determine home directory"))?;

        info!(
            "Listing dotfiles from home directory: {}",
            home_dir.display()
        );

        let mut dotfiles = Vec::new();

        for (file_name, file_type) in &self.common_dotfiles {
            let file_path = home_dir.join(file_name);
            let path_str = file_path.to_string_lossy().to_string();

            let dotfile = if file_path.exists() {
                let metadata = fs::metadata(&file_path)?;
                let modified = metadata
                    .modified()?
                    .duration_since(std::time::UNIX_EPOCH)?
                    .as_secs();

                DotFile {
                    name: file_name.to_string(),
                    path: path_str,
                    size: metadata.len(),
                    modified: DateTime::from_timestamp(modified as i64, 0)
                        .unwrap_or_else(|| Utc::now()),
                    exists: true,
                    readable: self.is_readable(&file_path),
                    writable: self.is_writable(&file_path),
                    file_type: file_type.clone(),
                }
            } else {
                DotFile {
                    name: file_name.to_string(),
                    path: path_str,
                    size: 0,
                    modified: Utc::now(),
                    exists: false,
                    readable: false,
                    writable: false,
                    file_type: file_type.clone(),
                }
            };

            dotfiles.push(dotfile);
        }

        info!("Listed {} dotfiles", dotfiles.len());
        Ok(dotfiles)
    }

    /// Read a dotfile's content with security validation
    pub async fn read_dotfile(&self, path: &str) -> Result<String> {
        let file_path = self.validate_and_resolve_path(path)?;

        // Debug logging
        info!(
            "Reading dotfile - requested path: {}, resolved path: {}",
            path,
            file_path.display()
        );

        // Check if file is readable
        if !self.is_readable(&file_path) {
            return Err(anyhow::anyhow!("File is not readable: {}", path));
        }

        // Read file content
        let content = fs::read_to_string(&file_path)
            .with_context(|| format!("Failed to read file: {}", path))?;

        info!(
            "Read dotfile: {} ({} bytes) from {}",
            path,
            content.len(),
            file_path.display()
        );

        // Check if this is .zshrc and log more details
        if path.contains("zshrc") {
            info!(".zshrc detected - checking content characteristics");
            let lines: Vec<&str> = content.lines().collect();
            info!("Total lines: {}", lines.len());
            info!(
                "First non-comment line: {:?}",
                lines
                    .iter()
                    .find(|l| !l.trim().starts_with('#') && !l.trim().is_empty())
            );
            info!("Contains 'Zim' setup: {}", content.contains("Zim"));
            info!("Contains 'autoload': {}", content.contains("autoload"));
        }

        // Log first 200 chars for debugging
        let preview = if content.len() > 200 {
            format!("{}...", &content[..200])
        } else {
            content.clone()
        };
        info!("Content preview: {}", preview.replace('\n', "\\n"));

        Ok(content)
    }

    /// Write content to a dotfile with backup
    pub async fn write_dotfile(&self, path: &str, content: &str) -> Result<()> {
        let file_path = self.validate_and_resolve_path(path)?;

        // Check if file/directory is writable
        if file_path.exists() && !self.is_writable(&file_path) {
            return Err(anyhow::anyhow!("File is not writable: {}", path));
        }

        // Create backup if file exists
        if file_path.exists() {
            self.create_backup(&file_path).await?;
        }

        // Ensure parent directory exists
        if let Some(parent) = file_path.parent() {
            fs::create_dir_all(parent)?;
        }

        // Write new content
        fs::write(&file_path, content)
            .with_context(|| format!("Failed to write file: {}", path))?;

        info!("Wrote dotfile: {} ({} bytes)", path, content.len());
        Ok(())
    }

    /// Create a backup of a file
    async fn create_backup(&self, file_path: &Path) -> Result<()> {
        let content = fs::read_to_string(file_path)?;
        let metadata = fs::metadata(file_path)?;

        let version = FileVersion {
            timestamp: Utc::now(),
            content: content.clone(),
            size: metadata.len(),
            hash: self.calculate_hash(&content),
        };

        let path_str = file_path.to_string_lossy().to_string();
        let mut history = self.history.write().await;
        let versions = history.entry(path_str.clone()).or_insert_with(Vec::new);

        // Keep only last 10 versions
        if versions.len() >= 10 {
            versions.remove(0);
        }

        versions.push(version);
        info!("Created backup for: {}", path_str);
        Ok(())
    }

    /// Get version history for a file
    pub async fn get_file_history(&self, path: &str) -> Result<Vec<FileVersion>> {
        let file_path = self.validate_and_resolve_path(path)?;
        let path_str = file_path.to_string_lossy().to_string();

        let history = self.history.read().await;
        Ok(history.get(&path_str).cloned().unwrap_or_default())
    }

    /// Restore a file from a specific version
    pub async fn restore_version(&self, path: &str, timestamp: DateTime<Utc>) -> Result<()> {
        let file_path = self.validate_and_resolve_path(path)?;
        let path_str = file_path.to_string_lossy().to_string();

        // Get the content to restore
        let content_to_restore = {
            let history = self.history.read().await;
            let versions = history
                .get(&path_str)
                .ok_or_else(|| anyhow::anyhow!("No history found for file"))?;

            let version = versions
                .iter()
                .find(|v| v.timestamp == timestamp)
                .ok_or_else(|| anyhow::anyhow!("Version not found"))?;

            version.content.clone()
        }; // Read lock is released here

        // Write the old version content
        self.write_dotfile(path, &content_to_restore).await?;

        Ok(())
    }

    /// Validate and resolve file path.
    /// All paths must resolve to within the user's home directory.
    fn validate_and_resolve_path(&self, path: &str) -> Result<PathBuf> {
        let home_dir = dirs::home_dir()
            .ok_or_else(|| anyhow::anyhow!("Could not determine home directory"))?;
        let canonical_home = home_dir
            .canonicalize()
            .unwrap_or_else(|_| home_dir.clone());

        // Resolve the path — absolute paths are re-rooted under home
        let file_path = if path.starts_with("~/") {
            home_dir.join(&path[2..])
        } else if path.starts_with('/') {
            // Absolute path: treat as relative to home to prevent traversal
            home_dir.join(path.trim_start_matches('/'))
        } else {
            home_dir.join(path)
        };

        // Canonicalize to resolve symlinks and relative components
        let canonical_path = if file_path.exists() {
            file_path.canonicalize()?
        } else {
            // For non-existent files, canonicalize the parent and append filename
            if let Some(parent) = file_path.parent() {
                if parent.exists() {
                    let canonical_parent = parent.canonicalize()?;
                    canonical_parent.join(file_path.file_name().unwrap_or_default())
                } else {
                    file_path
                }
            } else {
                file_path
            }
        };

        // Containment check: resolved path must be inside home directory
        if !canonical_path.starts_with(&canonical_home) {
            return Err(anyhow::anyhow!(
                "Access denied: path is outside the home directory"
            ));
        }

        Ok(canonical_path)
    }

    /// Check if a file is readable
    fn is_readable(&self, path: &Path) -> bool {
        fs::File::open(path).is_ok()
    }

    /// Check if a file is writable
    fn is_writable(&self, path: &Path) -> bool {
        use std::fs::OpenOptions;

        if path.exists() {
            OpenOptions::new().write(true).open(path).is_ok()
        } else if let Some(parent) = path.parent() {
            // Check if parent directory is writable
            parent.exists() && {
                let test_file = parent.join(".agentshell_write_test");
                let result = fs::write(&test_file, "test").is_ok();
                let _ = fs::remove_file(&test_file);
                result
            }
        } else {
            false
        }
    }

    /// Calculate a simple hash for version tracking
    fn calculate_hash(&self, content: &str) -> String {
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        let mut hasher = DefaultHasher::new();
        content.hash(&mut hasher);
        format!("{:x}", hasher.finish())
    }

    /// Read a file's raw bytes (for images, audio, etc.)
    pub async fn read_binary_file(&self, path: &str) -> Result<(Vec<u8>, &'static str)> {
        let file_path = self.validate_and_resolve_path(path)?;

        if !self.is_readable(&file_path) {
            return Err(anyhow::anyhow!("File is not readable: {}", path));
        }

        let bytes = fs::read(&file_path)
            .with_context(|| format!("Failed to read file: {}", path))?;
        let mime = Self::detect_mime_type(&file_path);

        info!("Read binary file: {} ({} bytes, {})", path, bytes.len(), mime);
        Ok((bytes, mime))
    }

    fn detect_mime_type(path: &Path) -> &'static str {
        match path.extension().and_then(|e| e.to_str()) {
            Some("jpg") | Some("jpeg") => "image/jpeg",
            Some("png") => "image/png",
            Some("gif") => "image/gif",
            Some("webp") => "image/webp",
            Some("bmp") => "image/bmp",
            Some("mp3") => "audio/mpeg",
            Some("wav") => "audio/wav",
            Some("ogg") => "audio/ogg",
            Some("m4a") | Some("aac") => "audio/aac",
            Some("flac") => "audio/flac",
            _ => "application/octet-stream",
        }
    }

    /// Get default templates for common config files
    pub fn get_templates(&self) -> Vec<DotFileTemplate> {
        vec![
            DotFileTemplate {
                name: "Basic .bashrc".to_string(),
                file_type: DotFileType::Shell,
                description: "Basic bash configuration with common aliases".to_string(),
                content: BASHRC_TEMPLATE.to_string(),
            },
            DotFileTemplate {
                name: "Basic .vimrc".to_string(),
                file_type: DotFileType::Vim,
                description: "Basic vim configuration with sensible defaults".to_string(),
                content: VIMRC_TEMPLATE.to_string(),
            },
            DotFileTemplate {
                name: "Basic .gitconfig".to_string(),
                file_type: DotFileType::Git,
                description: "Git configuration with useful aliases".to_string(),
                content: GITCONFIG_TEMPLATE.to_string(),
            },
            DotFileTemplate {
                name: "Basic .tmux.conf".to_string(),
                file_type: DotFileType::Tmux,
                description: "Tmux configuration with improved defaults".to_string(),
                content: TMUX_CONF_TEMPLATE.to_string(),
            },
        ]
    }
}

