        #[serde(rename = "modeId")]
        mode_id: String,
    },
    AcpPermissionResponse {
        #[serde(rename = "requestId")]
        request_id: String,
    },
    AcpHistoryLoaded {
        #[serde(rename = "sessionId")]
        session_id: String,
        messages: Vec<crate::chat_log::ChatMessage>,
        has_more: bool,
    },
    AcpSessionDeleted {
        #[serde(rename = "sessionId")]
        session_id: String,
        success: bool,
        error: Option<String>,
    },
    // File browser responses
    FilesList {
        path: String,
        entries: Vec<FileEntry>,
    },
    SessionCwd {
        #[serde(rename = "sessionName")]
        session_name: String,
        cwd: String,
    },
    // File management responses
    FilesDeleted {
        success: bool,
        paths: Vec<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        error: Option<String>,
    },
    FileRenamed {
        success: bool,
        #[serde(skip_serializing_if = "Option::is_none")]
        error: Option<String>,
    },
    // Binary file content response
    BinaryFileContent {
        path: String,
        #[serde(rename = "contentBase64")]
        content_base64: String,
        #[serde(rename = "mimeType")]
        mime_type: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        error: Option<String>,
    },
}

