        assert!(json.contains("pong"));
    }
}

use std::path::Path;
use std::sync::Arc;
use tracing::{error, info, warn};

use super::types::{send_message, WsState};
use crate::{types::*, AppState};

fn write_acp_session_file(session_id: &str, cwd: &str) {
    let home = match std::env::var("HOME") {
        Ok(h) => std::path::PathBuf::from(h),
        Err(_) => return,
    };

    let session_dir = home.join(".agentshell");
    let session_file = session_dir.join("acp_session");

    if let Err(e) = std::fs::create_dir_all(&session_dir) {
        warn!("Failed to create .agentshell directory: {}", e);
        return;
    }

    let ws_url = std::env::var("AGENTSHELL_WS_URL")
        .unwrap_or_else(|_| "ws://localhost:5173/ws".to_string());

    let session_json = serde_json::json!({
        "sessionId": session_id,
        "cwd": cwd,
        "wsUrl": ws_url
    });

    match std::fs::write(&session_file, session_json.to_string()) {
        Ok(_) => info!("Updated ACP session file: {:?}", session_file),
        Err(e) => warn!("Failed to write session file: {}", e),
    }
}

pub(crate) async fn handle(
    msg: WebSocketMessage,
    state: &mut WsState,
    app_state: Arc<AppState>,
) -> anyhow::Result<()> {
    match msg {
        // ACP message handlers
        WebSocketMessage::SelectBackend { backend } => {
            info!("Backend selection: {}", backend);

            if backend == "acp" {
                // Initialize ACP client globally in AppState
                let mut acp_guard = app_state.acp_client.write().await;
                if acp_guard.is_none() {
                    let (event_tx, mut event_rx) = tokio::sync::mpsc::channel::<crate::acp::AcpEvent>(100);
                    let mut client = crate::acp::AcpClient::new(event_tx);

                    match client.start().await {
                        Ok(init_result) => {
                            info!("ACP client initialized: {:?}", init_result.agent_info);
                            *acp_guard = Some(client);

                            // Spawn event handler
                            let broadcast_tx = app_state.broadcast_tx.clone();
                            let app_state_clone = app_state.clone();
                            tokio::spawn(async move {
                                while let Some(event) = event_rx.recv().await {
                                    match event {
                                        crate::acp::AcpEvent::SessionUpdate { session_id, update } => {
                                            let msg = match update {
                                                crate::acp::SessionUpdate::AgentMessageChunk { content } => {
                                                    let text = content.get("text").and_then(|v| v.as_str()).unwrap_or("").to_string();

                                                    // Merge into last assistant text row instead of inserting a new row per chunk
                                                    let session_key = format!("acp_{}", session_id);
                                                    match app_state_clone.chat_event_store.append_or_merge_text(
                                                        &session_key,
                                                        0,
                                                        "acp",
                                                        "assistant",
                                                        &text,
                                                    ) {
                                                        Ok(_) => {}
                                                        Err(e) => {
                                                            tracing::warn!("Failed to persist ACP message: {}", e);
                                                        }
                                                    }

                                                    ServerMessage::AcpMessageChunk {
                                                        session_id: session_id.clone(),
                                                        content: text,
                                                        is_thinking: false,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::AgentThoughtChunk { content } => {
                                                    ServerMessage::AcpMessageChunk {
                                                        session_id: session_id.clone(),
                                                        content: content.get("text").and_then(|v| v.as_str()).unwrap_or("").to_string(),
                                                        is_thinking: true,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::ToolCall { tool_call_id, title, kind, status, raw_input, .. } => {
                                                    let session_key = format!("acp_{}", session_id);
                                                    let chat_message = crate::chat_log::ChatMessage {
                                                        role: "assistant".to_string(),
                                                        timestamp: Some(chrono::Utc::now()),
                                                        blocks: vec![crate::chat_log::ContentBlock::ToolCall {
                                                            name: title.clone(),
                                                            summary: kind.clone(),
                                                            input: raw_input.clone(),
                                                        }],
                                                    };
                                                    if let Err(e) = app_state_clone.chat_event_store.append_message(&session_key, 0, "acp", &chat_message) {
                                                        tracing::warn!("Failed to persist ACP tool call: {}", e);
                                                    }
                                                    let input = raw_input.as_ref().map(|v| serde_json::to_string_pretty(v).unwrap_or_default());
                                                    ServerMessage::AcpToolCall {
                                                        session_id: session_id.clone(),
                                                        tool_call_id,
                                                        title,
                                                        kind,
                                                        status,
                                                        input,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::ToolCallUpdate { tool_call_id, status, content, .. } => {
                                                    let output = content.unwrap_or_default().iter()
                                                        .filter_map(|c| c.as_object())
                                                        .filter_map(|c| c.get("content").and_then(|v| v.as_object()))
                                                        .filter_map(|v| v.get("text").and_then(|t| t.as_str()))
                                                        .collect::<Vec<_>>()
                                                        .join("\n");
                                                    let session_key = format!("acp_{}", session_id);
                                                    let chat_message = crate::chat_log::ChatMessage {
                                                        role: "tool".to_string(),
                                                        timestamp: Some(chrono::Utc::now()),
                                                        blocks: vec![crate::chat_log::ContentBlock::ToolResult {
                                                            tool_name: tool_call_id.clone(),
                                                            summary: status.clone(),
                                                            content: if output.is_empty() { None } else { Some(output.clone()) },
                                                        }],
                                                    };
                                                    if let Err(e) = app_state_clone.chat_event_store.append_message(&session_key, 0, "acp", &chat_message) {
                                                        tracing::warn!("Failed to persist ACP tool result: {}", e);
                                                    }
                                                    ServerMessage::AcpToolResult {
                                                        session_id: session_id.clone(),
                                                        tool_call_id,
                                                        status,
                                                        output,
                                                    }
                                                }
                                                _ => continue,
                                            };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP message: {}", e);
                                            }
                                        }
                                        crate::acp::AcpEvent::PermissionRequest { request_id, session_id, tool_call, .. } => {
                                            let tool = tool_call.get("title").and_then(|v| v.as_str()).unwrap_or("unknown");
                                            let command = tool_call.get("rawInput")
                                                .and_then(|v| v.get("command"))
                                                .and_then(|v| v.as_str())
                                                .unwrap_or("");
                                            let msg = ServerMessage::AcpPermissionRequest {
                                                request_id,
                                                session_id,
                                                tool: tool.to_string(),
                                                command: command.to_string(),
                                            };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP permission request: {}", e);
                                            }
                                        }
                                        crate::acp::AcpEvent::Error { message } => {
                                            tracing::error!("ACP error: {}", message);
                                            let msg = ServerMessage::AcpError { message };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP error: {}", e);
                                            }
                                        }
                                    }
                                }
                            });

                            let response = ServerMessage::AcpInitialized { success: true, error: None };
                            send_message(&state.message_tx, response).await?;
                        }
                        Err(e) => {
                            error!("Failed to initialize ACP client: {}", e);
                            let response = ServerMessage::AcpInitialized { success: false, error: Some(e) };
                            send_message(&state.message_tx, response).await?;
                        }
                    }
                } else {
                    let response = ServerMessage::BackendSelected { backend: backend.clone() };
                    send_message(&state.message_tx, response).await?;
                }
            } else {
                let response = ServerMessage::BackendSelected { backend: backend.clone() };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpCreateSession { cwd } => {
            info!("ACP create session: {}", cwd);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.create_session(&cwd).await {
                    Ok(result) => {
                        info!("ACP session created: {:?}", result.session_id);
                        write_acp_session_file(&result.session_id, &cwd);
                        let response = ServerMessage::AcpSessionCreated {
                            session_id: result.session_id,
                            current_model_id: result.models.as_ref().map(|m| m.current_model_id.clone()),
                            available_models: None,
                            current_mode_id: result.modes.as_ref().map(|m| m.current_mode_id.clone()),
                            cwd: Some(cwd.clone()),
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        error!("Failed to create ACP session: {}", e);
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized. Select ACP backend first.".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpResumeSession { session_id, cwd } => {
            info!("ACP resume session: {} in {}", session_id, cwd);
            let acp_client = app_state.acp_client.clone();
            let message_tx = state.message_tx.clone();
            tokio::spawn(async move {
                let t_total = std::time::Instant::now();
                let acp_guard = acp_client.read().await;
                if let Some(client) = acp_guard.as_ref() {
                    match client.resume_session(&session_id, &cwd).await {
                        Ok(result) => {
                            info!("[TIMING] AcpResumeSession total {:?}", t_total.elapsed());
                            write_acp_session_file(&session_id, &cwd);
                            let _ = send_message(&message_tx, ServerMessage::AcpSessionCreated {
                                session_id: result.session_id,
                                current_model_id: result.models.as_ref().map(|m| m.current_model_id.clone()),
                                available_models: None,
                                current_mode_id: result.modes.as_ref().map(|m| m.current_mode_id.clone()),
                                cwd: None,
                            }).await;
                        }
                        Err(e) if e.starts_with("__already_active:") => {
                            // Session already active — skip resume, still notify Flutter
                            info!("[TIMING] AcpResumeSession skipped (already active) in {:?}", t_total.elapsed());
                            let _ = send_message(&message_tx, ServerMessage::AcpSessionCreated {
                                session_id: session_id.clone(),
                                current_model_id: None,
                                available_models: None,
                                current_mode_id: None,
                                cwd: None,
                            }).await;
                        }
                        Err(e) => {
                            error!("Failed to resume ACP session: {}", e);
                            let _ = send_message(&message_tx, ServerMessage::AcpError { message: e }).await;
                        }
                    }
                } else {
                    let _ = send_message(&message_tx, ServerMessage::AcpError {
                        message: "ACP client not initialized".to_string(),
                    }).await;
                }
            });
        }
        WebSocketMessage::AcpForkSession { session_id, cwd } => {
            info!("ACP fork session: {} in {}", session_id, cwd);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.fork_session(&session_id, &cwd).await {
                    Ok(result) => {
                        let response = ServerMessage::AcpSessionCreated {
                            session_id: result.session_id,
                            current_model_id: result.models.as_ref().map(|m| m.current_model_id.clone()),
                            available_models: None,
                            current_mode_id: result.modes.as_ref().map(|m| m.current_mode_id.clone()),
                            cwd: None,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        error!("Failed to fork ACP session: {}", e);
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpListSessions => {
            info!("ACP list sessions");
            let t_total = std::time::Instant::now();

            // Auto-initialize ACP client if not initialized
            let t_lock = std::time::Instant::now();
            let list_result = {
                let mut acp_guard = app_state.acp_client.write().await;
                info!("[TIMING] AcpListSessions write lock in {:?}", t_lock.elapsed());
                if acp_guard.is_none() {
                    info!("ACP client not initialized, auto-initializing...");
                    let (event_tx, mut event_rx) = tokio::sync::mpsc::channel::<crate::acp::AcpEvent>(100);
                    let mut client = crate::acp::AcpClient::new(event_tx);
                    match client.start().await {
                        Ok(init_result) => {
                            info!("ACP client auto-initialized: {:?}", init_result.agent_info);

                            // Spawn event handler
                            let broadcast_tx = app_state.broadcast_tx.clone();
                            let app_state_clone = app_state.clone();
                            tokio::spawn(async move {
                                while let Some(event) = event_rx.recv().await {
                                    match event {
                                        crate::acp::AcpEvent::SessionUpdate { session_id, update } => {
                                            let msg = match update {
                                                crate::acp::SessionUpdate::AgentMessageChunk { content } => {
                                                    let text = content.get("text").and_then(|v| v.as_str()).unwrap_or("").to_string();

                                                    // Merge into last assistant text row instead of inserting a new row per chunk
                                                    let session_key = format!("acp_{}", session_id);
                                                    if let Err(e) = app_state_clone.chat_event_store.append_or_merge_text(
                                                        &session_key,
                                                        0,
                                                        "acp",
                                                        "assistant",
                                                        &text,
                                                    ) {
                                                        tracing::warn!("Failed to persist ACP message: {}", e);
                                                    }

                                                    ServerMessage::AcpMessageChunk {
                                                        session_id: session_id.clone(),
                                                        content: text,
                                                        is_thinking: false,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::AgentThoughtChunk { content } => {
                                                    ServerMessage::AcpMessageChunk {
                                                        session_id: session_id.clone(),
                                                        content: content.get("text").and_then(|v| v.as_str()).unwrap_or("").to_string(),
                                                        is_thinking: true,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::ToolCall { tool_call_id, title, kind, status, raw_input, .. } => {
                                                    let session_key = format!("acp_{}", session_id);
                                                    let chat_message = crate::chat_log::ChatMessage {
                                                        role: "assistant".to_string(),
                                                        timestamp: Some(chrono::Utc::now()),
                                                        blocks: vec![crate::chat_log::ContentBlock::ToolCall {
                                                            name: title.clone(),
                                                            summary: kind.clone(),
                                                            input: raw_input.clone(),
                                                        }],
                                                    };
                                                    if let Err(e) = app_state_clone.chat_event_store.append_message(&session_key, 0, "acp", &chat_message) {
                                                        tracing::warn!("Failed to persist ACP tool call: {}", e);
                                                    }
                                                    let input = raw_input.as_ref().map(|v| serde_json::to_string_pretty(v).unwrap_or_default());
                                                    ServerMessage::AcpToolCall {
                                                        session_id: session_id.clone(),
                                                        tool_call_id,
                                                        title,
                                                        kind,
                                                        status,
                                                        input,
                                                    }
                                                }
                                                crate::acp::SessionUpdate::ToolCallUpdate { tool_call_id, status, content, .. } => {
                                                    let output = content.unwrap_or_default().iter()
                                                        .filter_map(|c| c.as_object())
                                                        .filter_map(|c| c.get("content").and_then(|v| v.as_object()))
                                                        .filter_map(|v| v.get("text").and_then(|t| t.as_str()))
                                                        .collect::<Vec<_>>()
                                                        .join("\n");
                                                    let session_key = format!("acp_{}", session_id);
                                                    let chat_message = crate::chat_log::ChatMessage {
                                                        role: "tool".to_string(),
                                                        timestamp: Some(chrono::Utc::now()),
                                                        blocks: vec![crate::chat_log::ContentBlock::ToolResult {
                                                            tool_name: tool_call_id.clone(),
                                                            summary: status.clone(),
                                                            content: if output.is_empty() { None } else { Some(output.clone()) },
                                                        }],
                                                    };
                                                    if let Err(e) = app_state_clone.chat_event_store.append_message(&session_key, 0, "acp", &chat_message) {
                                                        tracing::warn!("Failed to persist ACP tool result: {}", e);
                                                    }
                                                    ServerMessage::AcpToolResult {
                                                        session_id: session_id.clone(),
                                                        tool_call_id,
                                                        status,
                                                        output,
                                                    }
                                                }
                                                _ => continue,
                                            };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP message: {}", e);
                                            }
                                        }
                                        crate::acp::AcpEvent::PermissionRequest { request_id, session_id, tool_call, .. } => {
                                            let tool = tool_call.get("title").and_then(|v| v.as_str()).unwrap_or("unknown");
                                            let command = tool_call.get("rawInput")
                                                .and_then(|v| v.get("command"))
                                                .and_then(|v| v.as_str())
                                                .unwrap_or("");
                                            let msg = ServerMessage::AcpPermissionRequest {
                                                request_id,
                                                session_id,
                                                tool: tool.to_string(),
                                                command: command.to_string(),
                                            };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP permission request: {}", e);
                                            }
                                        }
                                        crate::acp::AcpEvent::Error { message } => {
                                            tracing::error!("ACP error: {}", message);
                                            let msg = ServerMessage::AcpError { message };
                                            if let Err(e) = broadcast_tx.send(msg) {
                                                tracing::error!("Failed to broadcast ACP error: {}", e);
                                            }
                                        }
                                    }
                                }
                            });

                            *acp_guard = Some(client);
                            acp_guard.as_mut().unwrap().list_sessions().await
                        }
                        Err(e) => {
                            error!("Failed to auto-initialize ACP client: {}", e);
                            let response = ServerMessage::AcpError {
                                message: format!("Failed to initialize ACP: {}", e),
                            };
                            send_message(&state.message_tx, response).await?;
                            return Ok(());
                        }
                    }
                } else {
                    acp_guard.as_mut().unwrap().list_sessions().await
                }
            };

            match list_result {
                Ok(result) => {
                    info!("[TIMING] AcpListSessions total {:?}", t_total.elapsed());
                    // Use DB directly to list all sessions across all projects
                    let db_path = crate::chat_log::watcher::find_opencode_db();
                    let sessions_result = match db_path {
                        Ok(p) => tokio::task::spawn_blocking(move || crate::chat_log::opencode_parser::list_all_sessions(&p))
                            .await.unwrap_or_else(|e| Err(anyhow::anyhow!("join error: {}", e))),
                        Err(e) => Err(anyhow::anyhow!("opencode.db not found: {}", e)),
                    };

                    match sessions_result {
                        Ok(all_sessions) => {
                            let deleted_ids = app_state.chat_event_store
                                .get_deleted_acp_session_ids()
                                .unwrap_or_default();
                            let sessions = all_sessions.into_iter()
                                .filter(|s| !deleted_ids.contains(&s.session_id))
                                .collect();
                            let response = ServerMessage::AcpSessionsListed { sessions };
                            send_message(&state.message_tx, response).await?;
                        }
                        Err(e) => {
                            // Fall back to ACP result
                            warn!("DB session list failed, using ACP fallback: {}", e);
                            let deleted_ids = app_state.chat_event_store
                                .get_deleted_acp_session_ids()
                                .unwrap_or_default();
                            let sessions = result.sessions.into_iter()
                                .filter(|s| !deleted_ids.contains(&s.session_id))
                                .collect();
                            let response = ServerMessage::AcpSessionsListed { sessions };
                            send_message(&state.message_tx, response).await?;
                        }
                    }
                }
                Err(e) => {
                    error!("Failed to list ACP sessions: {}", e);
                    let response = ServerMessage::AcpError {
                        message: e,
                    };
                    send_message(&state.message_tx, response).await?;
                }
            }
        }
        WebSocketMessage::AcpSendPrompt { session_id, message } => {
            info!("ACP send prompt to {}", session_id);
            // Spawn so the main loop is never blocked waiting for OpenCode's response
            let acp_client = app_state.acp_client.clone();
            let message_tx = state.message_tx.clone();
            tokio::spawn(async move {
                let acp_guard = acp_client.read().await;
                if let Some(client) = acp_guard.as_ref() {
                    let t = std::time::Instant::now();
                    match client.send_prompt(&session_id, &message).await {
                        Ok(_) => {
                            info!("[TIMING] send_prompt took {:?}", t.elapsed());
                            let _ = send_message(&message_tx, ServerMessage::AcpPromptSent { session_id }).await;
                        }
                        Err(e) => {
                            error!("Failed to send prompt (took {:?}): {}", t.elapsed(), e);
                            let _ = send_message(&message_tx, ServerMessage::AcpError { message: e }).await;
                        }
                    }
                } else {
                    let _ = send_message(&message_tx, ServerMessage::AcpError {
                        message: "ACP client not initialized".to_string(),
                    }).await;
                }
            });
        }
        WebSocketMessage::SendFileToAcpChat {
            session_id,
            file,
            prompt,
            cwd,
        } => {
            info!(
                "Received file to send to ACP chat: {} ({}) in cwd: {:?}",
                file.filename, file.mime_type, cwd
            );

            // Save file to storage (for display in chat)
            let file_id = match state
                .chat_file_storage
                .save_file(&file.data, &file.filename, &file.mime_type)
            {
                Ok(id) => id,
                Err(e) => {
                    error!("Failed to save file for ACP chat: {}", e);
                    return Ok(());
                }
            };

            // Also save to session's working directory (for AI to access)
            let mut file_path_str: Option<String> = None;
            if let Some(ref session_cwd) = cwd {
                match state
                    .chat_file_storage
                    .save_file_to_directory(&file.data, &file.filename, &file.mime_type, Path::new(session_cwd))
                {
                    Ok(path) => {
                        info!("File saved to session directory: {:?}", path);
                        file_path_str = Some(path.to_string_lossy().to_string());
                    }
                    Err(e) => {
                        error!("Failed to save file to session directory: {}", e);
                    }
                }
            }

            // Create content block based on mime type
            let block = if file.mime_type.starts_with("image/") {
                crate::chat_log::ContentBlock::Image {
                    id: file_id,
                    mime_type: file.mime_type.clone(),
                    alt_text: Some(file.filename.clone()),
                }
            } else if file.mime_type.starts_with("audio/") {
                crate::chat_log::ContentBlock::Audio {
                    id: file_id,
                    mime_type: file.mime_type.clone(),
                    duration_seconds: None,
                }
            } else {
                crate::chat_log::ContentBlock::File {
                    id: file_id,
                    filename: file.filename.clone(),
                    mime_type: file.mime_type.clone(),
                    size_bytes: Some((file.data.len() as f64 * 0.75) as u64),
                }
            };

            // Build message blocks
            let mut blocks = Vec::new();
            let mut prompt_text = String::new();

            // Add prompt if provided
            if let Some(ref p) = prompt {
                if !p.trim().is_empty() {
                    prompt_text = p.trim().to_string();
                    blocks.push(crate::chat_log::ContentBlock::Text {
                        text: p.trim().to_string(),
                    });
                }
            }
            blocks.push(block);

            let chat_message = crate::chat_log::ChatMessage {
                role: "user".to_string(),
                timestamp: Some(chrono::Utc::now()),
                blocks,
            };

            // Persist to chat_event_store
            let session_key = format!("acp_{}", session_id);
            if let Err(e) = app_state.chat_event_store.append_message(
                &session_key,
                0,
                "webhook-file",
                &chat_message,
            ) {
                warn!("Failed to persist ACP file message: {}", e);
            }

            // Broadcast to all connected clients
            // Flutter stores ACP sessions as "acp_{session_id}", so prefix accordingly
            let msg = ServerMessage::ChatFileMessage {
                session_name: format!("acp_{}", session_id),
                window_index: 0,
                message: chat_message.clone(),
            };
            info!("BROADCASTING ChatFileMessage for ACP session: {} (should NOT appear in tmux chat)", session_id);
            state.client_manager.broadcast(msg).await;

            // Send prompt to ACP session so AI can see the file
            let file_ref = file_path_str.clone().unwrap_or_else(|| format!("[File: {}]", file.filename));
            let combined = if prompt_text.is_empty() {
                file_ref
            } else {
                format!("{}\n\nHere is the file: {}", prompt_text, file_ref)
            };
            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                if let Err(e) = client.send_prompt(&session_id, &combined).await {
                    error!("Failed to send file prompt to ACP: {}", e);
                }
            }
        }
        WebSocketMessage::AcpCancelPrompt { session_id } => {
            info!("ACP cancel prompt: {}", session_id);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.cancel_prompt(&session_id).await {
                    Ok(_) => {
                        let response = ServerMessage::AcpPromptCancelled {
                            session_id: session_id.clone(),
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        error!("Failed to cancel prompt: {}", e);
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpSetModel { session_id, model_id } => {
            info!("ACP set model for {}: {}", session_id, model_id);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.set_model(&session_id, &model_id).await {
                    Ok(_) => {
                        let response = ServerMessage::AcpModelSet {
                            session_id: session_id.clone(),
                            model_id: model_id.clone(),
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpSetMode { session_id, mode_id } => {
            info!("ACP set mode for {}: {}", session_id, mode_id);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.set_mode(&session_id, &mode_id).await {
                    Ok(_) => {
                        let response = ServerMessage::AcpModeSet {
                            session_id: session_id.clone(),
                            mode_id: mode_id.clone(),
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpRespondPermission { request_id, option_id } => {
            info!("ACP respond to permission {} with option {}", request_id, option_id);

            let acp_guard = app_state.acp_client.read().await;
            if let Some(client) = acp_guard.as_ref() {
                match client.respond_to_permission(&request_id, &option_id).await {
                    Ok(_) => {
                        let response = ServerMessage::AcpPermissionResponse {
                            request_id: request_id.clone(),
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                    Err(e) => {
                        let response = ServerMessage::AcpError {
                            message: e,
                        };
                        send_message(&state.message_tx, response).await?;
                    }
                }
            } else {
                let response = ServerMessage::AcpError {
                    message: "ACP client not initialized".to_string(),
                };
                send_message(&state.message_tx, response).await?;
            }
        }
        WebSocketMessage::AcpLoadHistory { session_id, offset, limit } => {
            tracing::debug!("ACP load history: {} offset={:?} limit={:?}", session_id, offset, limit);

            // History loading doesn't require ACP client to be initialized - just read from database
            let offset = offset.unwrap_or(0);
            let limit = limit.unwrap_or(50);

            let session_key = format!("acp_{}", session_id);

            let messages = match app_state.chat_event_store.list_messages(&session_key, 0) {
                Ok(msgs) => msgs,
                Err(e) => {
                    error!("Failed to load ACP history: {}", e);
                    let response = ServerMessage::AcpError {
                        message: format!("Failed to load history: {}", e),
                    };
                    send_message(&state.message_tx, response).await?;
                    return Ok(());
                }
            };

            let total = messages.len();
            let has_more = offset + limit < total;
            let paginated: Vec<_> = messages.into_iter().skip(offset).take(limit).collect();

            let response = ServerMessage::AcpHistoryLoaded {
                session_id,
                messages: paginated,
                has_more,
            };
            send_message(&state.message_tx, response).await?;
        }
        WebSocketMessage::AcpClearHistory { session_id } => {
            let session_key = format!("acp_{}", session_id);
            if let Err(e) = app_state.chat_event_store.clear_messages(&session_key, 0) {
                tracing::warn!("Failed to clear ACP overlay for {}: {}", session_id, e);
            }
            // Set cleared_at so poll loop and future history loads skip old messages
            let timestamp = chrono::Utc::now().timestamp_millis();
            app_state.chat_clear_store.set_cleared_at(&session_key, 0, timestamp).await;
            send_message(
                &state.message_tx,
                ServerMessage::ChatLogCleared { session_name: session_key, window_index: 0, success: true, error: None },
            ).await?;
        }
        WebSocketMessage::AcpDeleteSession { session_id } => {
            info!("ACP delete session: {}", session_id);

            // The opencode ACP protocol has no session/delete method — sessions
            // persist in the daemon. We clear our local history and blocklist
            // the session ID so it's filtered out of future list responses.
            let session_key = format!("acp_{}", session_id);
            if let Err(e) = app_state.chat_event_store.clear_messages(&session_key, 0) {
                warn!("Failed to clear history for deleted ACP session {}: {}", session_id, e);
            }
            if let Err(e) = app_state.chat_event_store.mark_acp_session_deleted(&session_id) {
                warn!("Failed to mark ACP session {} as deleted: {}", session_id, e);
            }

            send_message(
                &state.message_tx,
                ServerMessage::AcpSessionDeleted { session_id, success: true, error: None },
            )
            .await?;
        }
        _ => {}
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use tokio::sync::{mpsc, Mutex};
    use tempfile::TempDir;
    use crate::websocket::{
        client_manager::ClientManager,
        types::{BroadcastMessage, WsState},
    };
    use crate::{
        chat_clear_store::ChatClearStore,
        chat_event_store::ChatEventStore,
        chat_file_storage::ChatFileStorage,
        types::WebSocketMessage,
    };

    fn make_state(dir: &std::path::Path) -> (WsState, mpsc::UnboundedReceiver<BroadcastMessage>, Arc<crate::AppState>) {
        let (tx, rx) = mpsc::unbounded_channel::<BroadcastMessage>();
        let (broadcast_tx, _) = mpsc::unbounded_channel();
        let chat_event_store = Arc::new(ChatEventStore::new(dir.to_path_buf()).unwrap());
        let chat_clear_store = Arc::new(ChatClearStore::new(&dir.to_path_buf()));
        let chat_file_storage = Arc::new(ChatFileStorage::new(dir.to_path_buf()));
        let client_manager = Arc::new(ClientManager::new());
        let ws_state = WsState {
            client_id: "test-client".to_string(),
            current_pty: Arc::new(Mutex::new(None)),
            current_session: Arc::new(Mutex::new(None)),
            current_window: Arc::new(Mutex::new(None)),
            audio_tx: None,
            message_tx: tx,
            chat_log_handle: Arc::new(Mutex::new(None)),
            chat_file_storage: chat_file_storage.clone(),
            chat_event_store: chat_event_store.clone(),
            chat_clear_store: chat_clear_store.clone(),
            client_manager: client_manager.clone(),
            acp_client: Arc::new(tokio::sync::RwLock::new(None)),
        };
        let app_state = Arc::new(crate::AppState {
            enable_audio_logs: false,
            broadcast_tx,
            client_manager,
            chat_file_storage,
            chat_event_store,
            chat_clear_store,
            acp_client: Arc::new(tokio::sync::RwLock::new(None)),
        });
        (ws_state, rx, app_state)
    }

    #[test]
    fn test_write_acp_session_file() {
        // Just ensure it doesn't panic
        write_acp_session_file("test-session-id", "/home/user/project");
    }

    #[tokio::test]
    async fn test_acp_load_history_empty() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, mut rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::AcpLoadHistory {
            session_id: "test-session".to_string(),
            offset: None,
            limit: None,
        }, &mut ws_state, app_state).await;
        assert!(result.is_ok());
        let msg = rx.try_recv().unwrap();
        let json = match msg {
            BroadcastMessage::Text(s) => s.as_ref().clone(),
            _ => panic!("Expected text"),
        };
        assert!(json.contains("AcpHistoryLoaded") || json.contains("messages"));
    }

    #[tokio::test]
    async fn test_acp_clear_history() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, mut rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::AcpClearHistory {
            session_id: "test-session".to_string(),
        }, &mut ws_state, app_state).await;
        assert!(result.is_ok());
        let msg = rx.try_recv().unwrap();
        let json = match msg {
            BroadcastMessage::Text(s) => s.as_ref().clone(),
            _ => panic!("Expected text"),
        };
        assert!(json.contains("Cleared") || json.contains("cleared") || json.contains("true"));
    }

    #[tokio::test]
    async fn test_acp_delete_session() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, mut rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::AcpDeleteSession {
            session_id: "session-to-delete".to_string(),
        }, &mut ws_state, app_state).await;
        assert!(result.is_ok());
        let msg = rx.try_recv().unwrap();
        let json = match msg {
            BroadcastMessage::Text(s) => s.as_ref().clone(),
            _ => panic!("Expected text"),
        };
        assert!(json.contains("Deleted") || json.contains("deleted") || json.contains("true"));
    }

    #[tokio::test]
    async fn test_acp_list_sessions_no_client_auto_init_fails() {
        // ACP client is None — AcpListSessions will try to auto-init ACP which will fail
        // since opencode binary likely isn't available in test environment
        let dir = TempDir::new().unwrap();
        let (mut ws_state, mut rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::AcpListSessions, &mut ws_state, app_state).await;
        assert!(result.is_ok());
        // May or may not send a response depending on timing
        let _ = rx.try_recv();
    }

    #[tokio::test]
    async fn test_acp_send_prompt_no_client() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, _rx, app_state) = make_state(dir.path());
        // Client is None — should handle gracefully
        let result = handle(WebSocketMessage::AcpSendPrompt {
            session_id: "test-sid".to_string(),
            message: "Hello".to_string(),
        }, &mut ws_state, app_state).await;
        assert!(result.is_ok());
    }

    #[tokio::test]
    async fn test_acp_cancel_prompt_no_client() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, _rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::AcpCancelPrompt {
            session_id: "test-sid".to_string(),
        }, &mut ws_state, app_state).await;
        assert!(result.is_ok());
    }

    #[tokio::test]
    async fn test_unknown_message_no_op() {
        let dir = TempDir::new().unwrap();
        let (mut ws_state, _rx, app_state) = make_state(dir.path());
        let result = handle(WebSocketMessage::Ping, &mut ws_state, app_state).await;
        assert!(result.is_ok());
    }
}

use std::sync::Arc;
use tracing::{error, info, warn};

use super::types::{send_message, merge_history_messages, WsState};
use crate::{types::*, AppState};

pub(crate) async fn handle(
    msg: WebSocketMessage,
    state: &mut WsState,
    _app_state: Arc<AppState>,
) -> anyhow::Result<()> {
    match msg {
        WebSocketMessage::WatchChatLog {
            session_name,
            window_index,
            limit,
        } => {
            info!(
                "Starting chat log watch for {}:{}",
                session_name, window_index
            );
            let message_tx = state.message_tx.clone();
            let chat_event_store = state.chat_event_store.clone();

            // Set current session and window for input handling
            *state.current_session.lock().await = Some(session_name.clone());
            *state.current_window.lock().await = Some(window_index);

            // Cancel any existing watcher
            {
                let mut handle_guard = state.chat_log_handle.lock().await;
                if let Some(handle) = handle_guard.take() {
                    tracing::info!("Stopping previous chat log watcher");
                    handle.abort();
                }
            }

            let chat_log_handle = state.chat_log_handle.clone();
            let chat_clear_store = state.chat_clear_store.clone();
            let handle = tokio::spawn(async move {
                tracing::info!(
                    "Detecting chat log for session '{}' window {}",
                    session_name,
                    window_index
                );

                // Get the clear timestamp if one exists
                let cleared_at = chat_clear_store
                    .get_cleared_at(&session_name, window_index)
                    .await;

                match crate::chat_log::watcher::detect_log_file(&session_name, window_index).await {
                    Ok((path, tool)) => {
                        let (event_tx, mut event_rx) = tokio::sync::mpsc::unbounded_channel();

                        // Spawn the file watcher -- the returned
                        // RecommendedWatcher must be kept alive for as long
                        // as we want notifications.
                        let _watcher =
                            match crate::chat_log::watcher::watch_log_file(&path, tool, event_tx, cleared_at, limit)
                                .await
                            {
                                Ok(w) => w,
                                Err(e) => {
                                    error!("Failed to start chat log watcher: {}", e);
                                    let _ = send_message(
                                        &message_tx,
                                        ServerMessage::ChatLogError {
                                            error: e.to_string(),
                                        },
                                    )
                                    .await;
                                    return;
                                }
                            };

                        // Forward events to WebSocket
                        let session_name_owned = session_name.clone();
                        while let Some(event) = event_rx.recv().await {
                            let msg = match event {
                                crate::chat_log::ChatLogEvent::History { messages, tool, has_more, total_count } => {
                                    let persisted_messages = match chat_event_store
                                        .list_messages(&session_name_owned, window_index)
                                    {
                                        Ok(stored) => stored,
                                        Err(e) => {
                                            warn!(
                                                "Failed to load persisted chat events for {}:{}: {}",
                                                session_name_owned, window_index, e
                                            );
                                            Vec::new()
                                        }
                                    };

                                    let merged_messages =
                                        merge_history_messages(messages, persisted_messages);
                                    tracing::info!(
                                        "Sending merged chat history: {} messages for session {}",
                                        merged_messages.len(),
                                        session_name_owned
                                    );
                                    ServerMessage::ChatHistory {
                                        session_name: session_name_owned.clone(),
                                        window_index,
                                        messages: merged_messages,
                                        tool: Some(tool),
                                        has_more,
                                        total_count,
                                    }
                                }
                                crate::chat_log::ChatLogEvent::NewMessage { message } => {
                                    tracing::info!(
                                        "Sending new chat message: role={} for session {}",
                                        message.role,
                                        session_name_owned
                                    );
                                    ServerMessage::ChatEvent {
                                        session_name: session_name_owned.clone(),
                                        window_index,
                                        message,
                                        source: None,
                                    }
                                }
                                crate::chat_log::ChatLogEvent::Error { error } => {
                                    tracing::warn!("Chat log error: {}", error);
                                    ServerMessage::ChatLogError { error }
                                }
                            };
                            if send_message(&message_tx, msg).await.is_err() {
                                break;
                            }
                        }
                    }
                    Err(e) => {
                        let _ = send_message(
                            &message_tx,
                            ServerMessage::ChatLogError {
                                error: e.to_string(),
                            },
                        )
                        .await;
                    }
                }
            });

            {
                let mut handle_guard = chat_log_handle.lock().await;
                *handle_guard = Some(handle);
            }
        }
        WebSocketMessage::WatchAcpChatLog { session_id, window_index, limit } => {
            let window_index = window_index.unwrap_or(0);
            let session_key = format!("acp_{}", session_id);

            tracing::debug!("Starting ACP chat log watch for session: {}", session_id);

            // Set current session for consistency
            *state.current_session.lock().await = Some(session_key.clone());
            *state.current_window.lock().await = Some(window_index);

            // Cancel any existing watcher
            {
                let mut handle_guard = state.chat_log_handle.lock().await;
                if let Some(handle) = handle_guard.take() {
                    tracing::info!("Stopping previous chat log watcher");
                    handle.abort();
                }
            }

            let message_tx = state.message_tx.clone();
            let chat_event_store = state.chat_event_store.clone();
            let chat_clear_store = state.chat_clear_store.clone();
            let chat_log_handle = state.chat_log_handle.clone();

            let handle = tokio::spawn(async move {
                // 1. Find OpenCode DB
                let db_path = match crate::chat_log::watcher::find_opencode_db() {
                    Ok(p) => p,
                    Err(e) => {
                        let _ = send_message(
                            &message_tx,
                            ServerMessage::ChatLogError { error: format!("OpenCode DB not found: {}", e) },
                        ).await;
                        return;
                    }
                };

                // 2. Get cleared_at
                let cleared_at = chat_clear_store.get_cleared_at(&session_key, window_index).await;

                // 3. Read full history from OpenCode DB
                let (opencode_messages, max_time_updated) = {
                    let db_path2 = db_path.clone();
                    let session_id2 = session_id.clone();
                    let t = std::time::Instant::now();
                    let result = tokio::task::spawn_blocking(move || {
                        crate::chat_log::opencode_parser::fetch_all_messages(&db_path2, &session_id2, cleared_at)
                    }).await.unwrap_or_else(|e| Err(anyhow::anyhow!("spawn_blocking failed: {}", e)))
                        .unwrap_or_else(|e| { tracing::warn!("Failed to read OpenCode history: {}", e); (vec![], 0) });
                    info!("[TIMING] fetch_all_messages({} msgs) took {:?}", result.0.len(), t.elapsed());
                    result
                };

                // 4. Read webhook/file overlay from AgentShell DB
                let t = std::time::Instant::now();
                let overlay = chat_event_store
                    .get_acp_overlay(&session_key, cleared_at)
                    .unwrap_or_else(|e| { tracing::warn!("Failed to read ACP overlay: {}", e); vec![] })
                    .into_iter()
                    .map(|e| (e.timestamp_millis, e.message))
                    .collect::<Vec<_>>();
                info!("[TIMING] get_acp_overlay({} msgs) took {:?}", overlay.len(), t.elapsed());

                // 5. Merge: interleave OpenCode messages and overlay by timestamp
                let mut combined: Vec<(i64, crate::chat_log::ChatMessage)> = opencode_messages
                    .into_iter()
                    .map(|m| {
                        let millis = m.timestamp
                            .map(|t| t.timestamp_millis())
                            .unwrap_or(0);
                        (millis, m)
                    })
                    .chain(overlay)
                    .collect();
                combined.sort_by_key(|(t, _)| *t);
                let all_messages: Vec<crate::chat_log::ChatMessage> = combined.into_iter().map(|(_, m)| m).collect();

                // 6. Apply pagination limit
                let limit_n = limit.unwrap_or(30);
                let total_count = all_messages.len();
                let has_more = total_count > limit_n;
                let messages = if has_more {
                    all_messages[total_count - limit_n..].to_vec()
                } else {
                    all_messages
                };

                // 7. Send history
                let _ = send_message(
                    &message_tx,
                    ServerMessage::ChatHistory {
                        session_name: session_key.clone(),
                        window_index,
                        messages,
                        tool: Some(crate::chat_log::AiTool::Opencode {
                            cwd: std::path::PathBuf::from("/"),
                            pid: 0,
                        }),
                        has_more,
                        total_count,
                    },
                ).await;

                // 7. Poll for new messages from OpenCode DB (no persistence)
                let mut opencode_state = crate::chat_log::opencode_parser::OpencodeState {
                    session_id: session_id.clone(),
                    last_time_updated: max_time_updated,
                    cleared_at,
                    pid: 0,
                    seen_text_lengths: std::collections::HashMap::new(),
                    seen_tool_calls: std::collections::HashSet::new(),
                    seen_tool_results: std::collections::HashSet::new(),
                };

                let mut interval = tokio::time::interval(std::time::Duration::from_millis(1000));
                loop {
                    interval.tick().await;
                    let t = std::time::Instant::now();
                    match crate::chat_log::opencode_parser::fetch_new_messages(&db_path, &mut opencode_state) {
                        Ok(new_messages) => {
                            let elapsed = t.elapsed();
                            if elapsed.as_millis() > 100 || !new_messages.is_empty() {
                                info!("[TIMING] poll fetch_new_messages({} new) took {:?}", new_messages.len(), elapsed);
                            }
                            for msg in new_messages {
                                if send_message(
                                    &message_tx,
                                    ServerMessage::ChatEvent {
                                        session_name: session_key.clone(),
                                        window_index,
                                        message: msg,
                                        source: Some("acp".to_string()),
                                    },
                                ).await.is_err() {
                                    tracing::debug!("ACP poll: client disconnected, stopping watcher");
                                    return;
                                }
                            }
                        }
                        Err(e) => tracing::debug!("ACP poll error: {}", e),
                    }
                }
            });

            *chat_log_handle.lock().await = Some(handle);
        }
        WebSocketMessage::LoadMoreChatHistory {
            session_name,
            window_index,
            offset,
            limit,
        } => {
            let message_tx = state.message_tx.clone();
            let chat_clear_store = state.chat_clear_store.clone();

            if session_name.starts_with("acp_") {
                // ACP session: re-fetch full history and slice the requested page
                let session_id = session_name[4..].to_string();
                let session_key = session_name.clone();

                tokio::spawn(async move {
                    let db_path = match crate::chat_log::watcher::find_opencode_db() {
                        Ok(p) => p,
                        Err(e) => {
                            let _ = send_message(&message_tx, ServerMessage::ChatLogError {
                                error: format!("OpenCode DB not found: {}", e),
                            }).await;
                            return;
                        }
                    };

                    let cleared_at = chat_clear_store.get_cleared_at(&session_key, window_index).await;

                    let (opencode_messages, _) = tokio::task::spawn_blocking(move || {
                        crate::chat_log::opencode_parser::fetch_all_messages(&db_path, &session_id, cleared_at)
                    }).await.unwrap_or_else(|e| Err(anyhow::anyhow!("spawn_blocking failed: {}", e)))
                        .unwrap_or_else(|e| { tracing::warn!("Failed to read OpenCode history: {}", e); (vec![], 0) });

                    let total_count = opencode_messages.len();
                    let start = total_count.saturating_sub(offset + limit);
                    let end = total_count.saturating_sub(offset);
                    let chunk: Vec<_> = opencode_messages[start..end].to_vec();
                    let has_more = start > 0;

                    let _ = send_message(&message_tx, ServerMessage::ChatHistoryChunk {
                        session_name: session_key,
                        window_index,
                        messages: chunk,
                        has_more,
                    }).await;
                });
            } else {
                // Claude Code session: re-parse log file and slice the requested page
                let session_name_owned = session_name.clone();
                tokio::spawn(async move {
                    let cleared_at = chat_clear_store.get_cleared_at(&session_name_owned, window_index).await;

                    let (path, tool) = match crate::chat_log::watcher::detect_log_file(&session_name_owned, window_index).await {
                        Ok(r) => r,
                        Err(e) => {
                            let _ = send_message(&message_tx, ServerMessage::ChatLogError {
                                error: format!("Failed to detect log file: {}", e),
                            }).await;
                            return;
                        }
                    };

                    // Spawn a one-shot channel to collect the initial History event.
                    let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel();
                    if crate::chat_log::watcher::watch_log_file(&path, tool, tx, cleared_at, None).await.is_err() {
                        return;
                    }
                    if let Some(crate::chat_log::ChatLogEvent::History { messages, .. }) = rx.recv().await {
                        let total_count = messages.len();
                        let start = total_count.saturating_sub(offset + limit);
                        let end = total_count.saturating_sub(offset);
                        let chunk: Vec<_> = messages[start..end].to_vec();
                        let has_more = start > 0;

                        let _ = send_message(&message_tx, ServerMessage::ChatHistoryChunk {
                            session_name: session_name_owned,
                            window_index,
                            messages: chunk,
                            has_more,
                        }).await;
                    }
                });
            }
        }
        WebSocketMessage::UnwatchChatLog => {
            info!("Stopping chat log watch");
            let mut handle_guard = state.chat_log_handle.lock().await;
            if let Some(handle) = handle_guard.take() {
                handle.abort();
            }
        }
        WebSocketMessage::ClearChatLog {
            session_name,
            window_index,
        } => {
            info!(
                "Clearing chat log for session {}:{}",
                session_name, window_index
            );

            // Stop current watcher if running
            {
                let mut handle_guard = state.chat_log_handle.lock().await;
                if let Some(handle) = handle_guard.take() {
                    handle.abort();
                }
            }

            // Set the clear timestamp
            let timestamp = chrono::Utc::now().timestamp_millis();
            state
                .chat_clear_store
                .set_cleared_at(&session_name, window_index, timestamp)
                .await;

            // Also clear persisted messages
            if let Err(e) = state
                .chat_event_store
                .clear_messages(&session_name, window_index)
            {
                warn!(
                    "Failed to clear persisted messages for {}:{}: {}",
                    session_name, window_index, e
                );
            }

            // Send confirmation to client
            let _ = send_message(
                &state.message_tx,
                ServerMessage::ChatLogCleared {
                    session_name: session_name.clone(),
                    window_index,
                    success: true,
                    error: None,
                },
            )
            .await;

            // Restart the watcher with the clear timestamp
            state
                .current_session
                .lock()
                .await
                .clone_from(&Some(session_name.clone()));
            state
                .current_window
                .lock()
                .await
                .clone_from(&Some(window_index));

            let message_tx = state.message_tx.clone();
            let chat_event_store = state.chat_event_store.clone();
            let chat_clear_store = state.chat_clear_store.clone();
            let session_name_owned = session_name.clone();
            let window_index_owned = window_index;

            let handle = tokio::spawn(async move {
                match crate::chat_log::watcher::detect_log_file(&session_name_owned, window_index_owned)
                    .await
                {
                    Ok((path, tool)) => {
                        let (event_tx, mut event_rx) =
                            tokio::sync::mpsc::unbounded_channel();

                        // Get the clear timestamp
                        let cleared_at = chat_clear_store
                            .get_cleared_at(&session_name_owned, window_index_owned)
                            .await;

                        let _watcher = match crate::chat_log::watcher::watch_log_file(
                            &path,
                            tool.clone(),
                            event_tx,
                            cleared_at,
                            None,
                        )
                        .await
                        {
                            Ok(w) => w,
                            Err(e) => {
                                error!("Failed to start chat log watcher: {}", e);
                                let _ = send_message(
                                    &message_tx,
                                    ServerMessage::ChatLogError {
                                        error: e.to_string(),
                                    },
                                )
                                .await;
                                return;
                            }
                        };

                        // Forward events to WebSocket
                        while let Some(event) = event_rx.recv().await {
                            let msg = match event {
                                crate::chat_log::ChatLogEvent::History { messages, tool, has_more, total_count } => {
                                    let persisted_messages = match chat_event_store
                                        .list_messages(&session_name_owned, window_index_owned)
                                    {
                                        Ok(stored) => stored,
                                        Err(e) => {
                                            warn!(
                                                "Failed to load persisted chat events for {}:{}: {}",
                                                session_name_owned, window_index_owned, e
                                            );
                                            Vec::new()
                                        }
                                    };

                                    let merged_messages =
                                        merge_history_messages(
                                            messages,
                                            persisted_messages,
                                        );

                                    ServerMessage::ChatHistory {
                                        session_name: session_name_owned.clone(),
                                        window_index: window_index_owned,
                                        messages: merged_messages,
                                        tool: Some(tool),
                                        has_more,
                                        total_count,
                                    }
                                }
                                crate::chat_log::ChatLogEvent::NewMessage { message } => {
                                    ServerMessage::ChatEvent {
                                        session_name: session_name_owned.clone(),
                                        window_index: window_index_owned,
                                        message,
                                        source: None,
                                    }
                                }
                                crate::chat_log::ChatLogEvent::Error { error } => {
                                    tracing::warn!("Chat log error: {}", error);
                                    ServerMessage::ChatLogError { error }
                                }
                            };
                            if send_message(&message_tx, msg).await.is_err() {
                                break;
                            }
                        }
                    }
                    Err(e) => {
                        let _ = send_message(
                            &message_tx,
                            ServerMessage::ChatLogError {
                                error: e.to_string(),
                            },
                        )
                        .await;
                    }
                }
            });

            {
                let mut handle_guard = state.chat_log_handle.lock().await;
                *handle_guard = Some(handle);
            }
        }
        WebSocketMessage::SendFileToChat {
            session_name,
            window_index,
            file,
            prompt,
        } => {
            info!(
                "Received file to send to chat: {} ({})",
                file.filename, file.mime_type
            );

            // Get tmux session working directory
            let session_path = crate::tmux::get_session_path(&session_name);

            // Save file to session directory if we have a valid path
            let file_path_str = if let Some(ref session_path) = session_path {
                match state
                    .chat_file_storage
                    .save_file_to_directory(
                        &file.data,
                        &file.filename,
                        &file.mime_type,
                        session_path,
                    ) {
                    Ok(path) => {
                        info!("File saved to session directory: {:?}", path);
                        Some(path.to_string_lossy().to_string())
                    }
                    Err(e) => {
                        error!("Failed to save file to session directory: {}", e);
                        None
                    }
                }
            } else {
                error!("Could not get session path for {}", session_name);
                None
            };

            // Save file to chat_files for display purposes (UUID-based)
            let file_id = match state
                .chat_file_storage
                .save_file(&file.data, &file.filename, &file.mime_type)
            {
                Ok(id) => id,
                Err(e) => {
                    error!("Failed to save file for display: {}", e);
                    return Ok(());
                }
            };

            // Build combined text (prompt + file path)
            let combined_text = match (&prompt, &file_path_str) {
                (Some(text), Some(path)) if !text.trim().is_empty() => {
                    format!("{}\n\nHere is the file: {}", text.trim(), path)
                }
                (Some(_), Some(path)) => format!("Here is the file: {}", path),
                (Some(text), None) if !text.trim().is_empty() => text.trim().to_string(),
                (None, Some(path)) => format!("Here is the file: {}", path),
                _ => String::new(),
            };

            // Create content block based on mime type
            let block = if file.mime_type.starts_with("image/") {
                crate::chat_log::ContentBlock::Image {
                    id: file_id,
                    mime_type: file.mime_type.clone(),
                    alt_text: Some(file.filename.clone()),
                }
            } else if file.mime_type.starts_with("audio/") {
                crate::chat_log::ContentBlock::Audio {
                    id: file_id,
                    mime_type: file.mime_type.clone(),
                    duration_seconds: None,
                }
            } else {
                crate::chat_log::ContentBlock::File {
                    id: file_id,
                    filename: file.filename.clone(),
                    mime_type: file.mime_type.clone(),
                    size_bytes: Some((file.data.len() as f64 * 0.75) as u64),
                }
            };

            // Build message blocks: text (if prompt provided) + file
            let mut blocks = Vec::new();
            let combined_text_for_tmux = combined_text.clone();
            if !combined_text.is_empty() {
                blocks.push(crate::chat_log::ContentBlock::Text {
                    text: combined_text,
                });
            }
            blocks.push(block);

            let chat_message = crate::chat_log::ChatMessage {
                role: "user".to_string(),
                timestamp: Some(chrono::Utc::now()),
                blocks,
            };

            if let Err(e) = state.chat_event_store.append_message(
                &session_name,
                window_index,
                "webhook-file",
                &chat_message,
            ) {
                warn!(
                    "Failed to persist chat file message for {}:{}: {}",
                    session_name, window_index, e
                );
            }

            // Broadcast to all connected clients watching this session
            let msg = ServerMessage::ChatFileMessage {
                session_name: session_name.clone(),
                window_index,
                message: chat_message,
            };

            // Use client_manager.broadcast to send to ALL connected clients
            state.client_manager.broadcast(msg).await;

            // Send the combined text (prompt + file path) to the tmux session
            // so the AI tool (OpenCode/Claude) actually receives the file reference
            if !combined_text_for_tmux.is_empty() {
                let target = format!("{}:{}", session_name, window_index);
                let text = combined_text_for_tmux.trim_end_matches('\n');

                // Two separate tmux calls: text first, then Enter.
                let _ = tokio::process::Command::new("tmux")
                    .args(&["send-keys", "-t", &target, "-l", text])
                    .output()
                    .await;
                let result = tokio::process::Command::new("tmux")
                    .args(&["send-keys", "-t", &target, "Enter"])
                    .output()
                    .await;

                match result {
                    Ok(output) if output.status.success() => {
                        info!("Sent file prompt to tmux: {:?}", text);
                    }
                    Ok(output) => {
                        error!("tmux send-keys failed for {}: {}", target, output.status);
                    }
                    Err(e) => {
                        error!("Failed to send file prompt to tmux session {}: {}", target, e);
                    }
                }
            }
        }
        WebSocketMessage::SendChatMessage {
            session_name,
            window_index,
            message,
            notify,
        } => {
            info!(
                "Received chat message to send: {} (notify: {:?})",
                message, notify
            );

            if message.trim().is_empty() {
                warn!("Empty message received, skipping");
                return Ok(());
            }

            let chat_message = crate::chat_log::ChatMessage {
                role: "user".to_string(),
                timestamp: Some(chrono::Utc::now()),
                blocks: vec![crate::chat_log::ContentBlock::Text {
                    text: message.trim().to_string(),
                }],
            };

            if let Err(e) = state.chat_event_store.append_message(
                &session_name,
                window_index,
                "webhook",
                &chat_message,
            ) {
                warn!(
                    "Failed to persist chat message for {}:{}: {}",
                    session_name, window_index, e
                );
            }

            let msg = ServerMessage::ChatEvent {
                session_name: session_name.clone(),
                window_index,
                message: chat_message,
                source: Some("webhook".to_string()),
            };

            state.client_manager.broadcast(msg).await;

            let should_notify = notify.unwrap_or(true);
            if should_notify {
                let notify_msg = ServerMessage::ChatNotification {
                    session_name: session_name.clone(),
                    window_index,
                    preview: if message.len() > 50 {
                        format!("{}...", &message[..50])
                    } else {
                        message.clone()
                    },
                };
                state.client_manager.broadcast(notify_msg).await;
            }

            let target = format!("{}:{}", session_name, window_index);
            let text = message.trim();

            // Two separate tmux calls: text first, then Enter.
            let _ = tokio::process::Command::new("tmux")
                .args(&["send-keys", "-t", &target, "-l", text])
                .output()
                .await;
            let result = tokio::process::Command::new("tmux")
                .args(&["send-keys", "-t", &target, "Enter"])
                .output()
                .await;

            match result {
                Ok(output) if output.status.success() => {
                    info!("Sent chat message to tmux: {:?}", text);
                }
                Ok(output) => {
                    error!("tmux send-keys failed for {}: {}", target, output.status);
                }
                Err(e) => {
                    error!("Failed to send chat message to tmux session {}: {}", target, e);
                }
            }
        }
        _ => {}
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use tokio::sync::{mpsc, Mutex};
    use tempfile::TempDir;
    use crate::websocket::{
        client_manager::ClientManager,
        types::{BroadcastMessage, WsState},
    };
    use crate::{
        chat_clear_store::ChatClearStore,
        chat_event_store::ChatEventStore,
        chat_file_storage::ChatFileStorage,
        types::WebSocketMessage,
    };
    use base64::Engine;

    fn make_ws_state(dir: &std::path::Path) -> (WsState, mpsc::UnboundedReceiver<BroadcastMessage>) {
        let (tx, rx) = mpsc::unbounded_channel::<BroadcastMessage>();
        let chat_event_store = Arc::new(ChatEventStore::new(dir.to_path_buf()).unwrap());
        let chat_clear_store = Arc::new(ChatClearStore::new(&dir.to_path_buf()));
        let chat_file_storage = Arc::new(ChatFileStorage::new(dir.to_path_buf()));
        let client_manager = Arc::new(ClientManager::new());
        let state = WsState {
            client_id: "test-client".to_string(),
            current_pty: Arc::new(Mutex::new(None)),
            current_session: Arc::new(Mutex::new(None)),
            current_window: Arc::new(Mutex::new(None)),
            audio_tx: None,
            message_tx: tx,
            chat_log_handle: Arc::new(Mutex::new(None)),
            chat_file_storage,
            chat_event_store,
            chat_clear_store,
            client_manager,
            acp_client: Arc::new(tokio::sync::RwLock::new(None)),
        };
        (state, rx)
    }

    #[tokio::test]
    async fn test_unwatch_chat_log() {
        let dir = TempDir::new().unwrap();
        let (mut state, _rx) = make_ws_state(dir.path());
        let result = handle(WebSocketMessage::UnwatchChatLog, &mut state, make_app_state(dir.path())).await;
        assert!(result.is_ok());
    }

    #[tokio::test]
    async fn test_clear_chat_log() {
        let dir = TempDir::new().unwrap();
        let (mut state, mut rx) = make_ws_state(dir.path());
        let result = handle(WebSocketMessage::ClearChatLog {
            session_name: "test-session".to_string(),
            window_index: 0,
        }, &mut state, make_app_state(dir.path())).await;
        assert!(result.is_ok());
        // Should have received ChatLogCleared response
        let msg = rx.try_recv().unwrap();
        let json = match msg {
            BroadcastMessage::Text(s) => s.as_ref().clone(),
            _ => panic!("Expected text"),
        };
        assert!(json.contains("Cleared") || json.contains("cleared"));
    }

    #[tokio::test]
    async fn test_load_more_chat_history_acp_session() {
        let dir = TempDir::new().unwrap();
        let (mut state, _rx) = make_ws_state(dir.path());
        // acp_ prefix sessions try to read opencode DB — it won't exist, error handled gracefully
        let result = handle(WebSocketMessage::LoadMoreChatHistory {
            session_name: "acp_test-session-id".to_string(),
            window_index: 0,
            offset: 0,
            limit: 20,
        }, &mut state, make_app_state(dir.path())).await;
